        [InGameTest(Category = "RevertVesselStrip", Scene = GameScenes.FLIGHT,
            Description = "BUG-H: the live active vessel's Vessel.id Guid protects it from a same-pid DIFFERENT-launch recording, but is recognized when the recorded Guid matches")]
        public void RevertStrip_LiveGuidGate_ProtectsDifferentLaunch()
        {
            var v = FlightGlobals.ActiveVessel;
            if (v == null)
            {
                InGameAssert.Skip("No active vessel in Flight scene");
                return;
            }

            uint pid = v.persistentId;
            string liveGuid = v.id != System.Guid.Empty ? v.id.ToString("N") : null;
            InGameAssert.IsFalse(string.IsNullOrEmpty(liveGuid),
                "A live flight vessel must carry a non-empty Vessel.id Guid for the launch-identity gate");

            // A recording that ADOPTED a DIFFERENT real launch of the same craft: identical
            // craft-baked pid, but a distinct launch Guid. Even with NO scope whitelist, the live
            // vessel must never be deletable in its place (the core BUG-H invariant).
            string differentGuid = System.Guid.NewGuid().ToString("N");
            if (string.Equals(differentGuid, liveGuid, System.StringComparison.OrdinalIgnoreCase))
                differentGuid = System.Guid.NewGuid().ToString("N");

            var differentLaunch = new Recording
            {
                VesselName = v.vesselName,
                VesselPersistentId = pid,
                SpawnedVesselPersistentId = pid, // adoption stamp (the colliding shape)
                RecordedVesselGuid = differentGuid,
            };
            var recordings = new System.Collections.Generic.List<Recording> { differentLaunch };

            bool stripDifferent = ParsekScenario.ShouldStripVesselForRecordings(
                pid, liveGuid, v.situation, recordings,
                matchSource: false, skipPrelaunch: false,
                requireWhitelist: false, preExistingWhitelist: null,
                out _, out string reasonDifferent);
            InGameAssert.IsFalse(stripDifferent,
                $"Live vessel (pid={pid}, guid={liveGuid}) must NOT be strippable for a different-launch " +
                $"recording (guid={differentGuid}); reason={reasonDifferent}");

            // The same-launch recording (recorded Guid matches the live vessel) IS recognized.
            var sameLaunch = new Recording
            {
                VesselName = v.vesselName,
                VesselPersistentId = pid,
                SpawnedVesselPersistentId = pid,
                RecordedVesselGuid = liveGuid,
            };
            InGameAssert.IsTrue(
                VesselLaunchIdentity.LiveVesselIsRecordedSpawn(sameLaunch, pid, liveGuid),
                "Live vessel must be recognized as the same launch when the recorded Guid matches");

            ParsekLog.Info("TestRunner",
                $"RevertStrip live-Guid gate OK: pid={pid} liveGuid={liveGuid} protected vs differentGuid={differentGuid}");
        }

        [InGameTest(Category = "SpawnTerminalOrbit", Scene = GameScenes.FLIGHT,
            Description = "Recording with a stale on-rails OrbitSegment plus a fresh post-burn ExoBallistic Absolute tail frame derives a stable circular orbit at spawn time")]
        public void TerminalOrbitFromTail_DerivesPostBurnCircularOrbit()
        {
            CelestialBody kerbin = FlightGlobals.Bodies?.Find(b => b.bodyName == "Kerbin");
            if (kerbin == null)
            {
                InGameAssert.Skip("Kerbin not found in FlightGlobals.Bodies");
                return;
            }

            // Mirror the Kerbal X bug shape from logs/2026-05-10_1713: one stored OrbitSegment
            // covering the on-rails coast (sub-orbital, periapsis below ground), then an
            // ExoBallistic Absolute TrackSection containing a single post-burn frame
            // whose state vector defines a circular ~205 km orbit. The tail velocity is
            // built from the live body transform so the assertion pins the reseed frame
            // conversion instead of a historical body-rotation phase. The fix must walk
            // past the segment, build the orbit from the tail frame, and the resulting
            // periapsis must clear the atmosphere.
            const double subOrbitalSegmentEndUT = 958.87;
            const double postBurnFrameUT = 977.93;
            const double postBurnAlt = 203587.0; // metres
            const double postBurnLat = 0.0;
            const double postBurnLon = 8.5604;
            Vector3d postBurnWorldPos = kerbin.GetWorldSurfacePosition(postBurnLat, postBurnLon, postBurnAlt);
            Vector3d postBurnRadial = (postBurnWorldPos - kerbin.position).normalized;
            // Cross order matters. OrbitReseed.FromLatLonAltAndRecordedVelocity
            // applies `.xzy` to both position and velocity before passing them to
            // Orbit.UpdateFromStateVectors, so what determines the orbit shape is
            // `h_zup = pos_zup × vel_zup` — and `.xzy` is an axis swap (odd
            // permutation), so `(r × v).xzy ≠ r_zup × v_zup`; the cross product
            // must be evaluated AFTER the swap, not before. For a prograde
            // equatorial orbit `h_zup` must point along +Z_zup (Kerbin's spin
            // axis in Planetarium-Zup coords). `Cross(radial, Y)` builds the
            // Unity-Yup velocity whose .xzy form satisfies that; the reversed
            // `Cross(Y, radial)` produces the opposite velocity, lands `h_zup`
            // along −Z_zup, and the orbit reads as inclination = 180°.
            Vector3d postBurnTangent = Vector3d.Cross(postBurnRadial, new Vector3d(0.0, 1.0, 0.0));
            if (postBurnTangent.sqrMagnitude < 1e-12)
                postBurnTangent = Vector3d.Cross(postBurnRadial, new Vector3d(1.0, 0.0, 0.0));
            postBurnTangent = postBurnTangent.normalized;
            double postBurnSpeed = System.Math.Sqrt(kerbin.gravParameter / (postBurnWorldPos - kerbin.position).magnitude);
            Vector3d postBurnVelYup = postBurnTangent * postBurnSpeed;
            UnityEngine.Vector3 postBurnVel = new UnityEngine.Vector3(
                (float)postBurnVelYup.x,
                (float)postBurnVelYup.y,
                (float)postBurnVelYup.z);

            var rec = new Recording { RecordingId = "ingame-tail-derived-orbit" };
            rec.OrbitSegments.Add(new OrbitSegment
            {
                bodyName = "Kerbin",
                startUT = 477.33,
                endUT = subOrbitalSegmentEndUT,
                inclination = 0.7917,
                eccentricity = 0.2046,
                semiMajorAxis = 667047.84, // periapsis = -69 km, apoapsis = 203 km
                longitudeOfAscendingNode = 22.89,
                argumentOfPeriapsis = 271.44,
                meanAnomalyAtEpoch = 1.4262,
                epoch = 477.33
            });
            var coastSection = new TrackSection
            {
                environment = SegmentEnvironment.ExoBallistic,
                referenceFrame = ReferenceFrame.Absolute,
                startUT = postBurnFrameUT,
                endUT = postBurnFrameUT,
                frames = new System.Collections.Generic.List<TrajectoryPoint>
                {
                    new TrajectoryPoint
                    {
                        ut = postBurnFrameUT,
                        latitude = postBurnLat,
                        longitude = postBurnLon,
                        altitude = postBurnAlt,
                        rotation = UnityEngine.Quaternion.identity,
                        velocity = postBurnVel,
                        bodyName = "Kerbin"
                    }
                }
            };
            rec.TrackSections.Add(coastSection);

            // spawnUT == tailUT keeps the rotation-drift clamp at zero.
            bool helperOk = VesselSpawner.TryDeriveTerminalOrbitSeedFromTrajectoryTail(
                rec, kerbin, postBurnFrameUT,
                out double inclination,
                out double eccentricity,
                out double semiMajorAxis,
                out _, out _, out _, out _,
                out string bodyName,
                out string declineReason);

            InGameAssert.IsTrue(helperOk,
                $"TryDeriveTerminalOrbitSeedFromTrajectoryTail should succeed (declineReason={declineReason ?? "(null)"})");
            InGameAssert.AreEqual("Kerbin", bodyName);
            InGameAssert.IsTrue(semiMajorAxis > 0.0,
                $"Derived sma must be positive, got {semiMajorAxis}");
            InGameAssert.IsTrue(eccentricity >= 0.0 && eccentricity < 1.0,
                $"Derived eccentricity must be in [0,1), got {eccentricity}");

            double periAlt = semiMajorAxis * (1.0 - eccentricity) - kerbin.Radius;
            double apoAlt = semiMajorAxis * (1.0 + eccentricity) - kerbin.Radius;

            // Drive the full TryBuildRecordedTerminalOrbitForSpawn → safety-evaluate
            // pipeline that the production spawn path runs. The bug repro requires the
            // safety check to ACCEPT (not just that the helper produces an orbit).
            bool buildOk = VesselSpawner.TryBuildRecordedTerminalOrbitForSpawn(
                rec, kerbin, postBurnFrameUT, out Orbit propagatedOrbit);
            InGameAssert.IsTrue(buildOk,
                "TryBuildRecordedTerminalOrbitForSpawn should produce an orbit when tail-derive succeeds");
            InGameAssert.IsNotNull(propagatedOrbit, "Propagated orbit should be non-null");

            double safeAlt = TerminalOrbitSpawnSafety.ComputeSafeAltitude(
                kerbin.atmosphereDepth, TerminalOrbitSpawnSafety.DefaultSafetyMarginMeters);
            var decision = TerminalOrbitSpawnSafety.Evaluate(
                currentAltitude: postBurnAlt,
                atmosphereDepth: kerbin.atmosphereDepth,
                safetyMargin: TerminalOrbitSpawnSafety.DefaultSafetyMarginMeters,
                periapsisAltitude: periAlt,
                apoapsisAltitude: apoAlt);

            // The whole point of the fix: the recording's stale segment alone would
            // produce decision=CannotSpawnSafely with reason=periapsis-below-safe-altitude.
            // After tail-derive, the safety check must return SpawnNow (or at minimum NOT
            // CannotSpawnSafely). Stronger than periAlt > atmosphereDepth — the safety
            // margin (typically 5 km above atmosphere) is what TerminalOrbitSpawnSafety
            // actually gates on at spawn time.
            InGameAssert.IsTrue(periAlt > safeAlt,
                $"Derived periapsis ({periAlt:F0} m) must clear safe altitude ({safeAlt:F0} m)");
            InGameAssert.AreEqual(
                TerminalOrbitSpawnSafetyAction.SpawnNow,
                decision.Action,
                $"Safety decision for tail-derived orbit should be SpawnNow, got {decision.Action} reason={decision.ReasonCode}");

            // Pin the orbit shape itself, not just the safety verdict. The `SpawnNow`
            // outcome is forgiving — a near-circular ~200 km orbit clears safety even
            // when `body.position` and `.xzy` are wrong, because the magnitude error is
            // small for a Kerbin-orbit-Kerbin-active-vessel scene. The shape check
            // below catches the frame-mismatch class of bug: skipping `(pos -
            // body.position)` corrupts |pos|, which corrupts sma AND inclination AND
            // ecc; skipping `.xzy` rotates LAN/argPe but leaves sma invariant. So the
            // ecc bound is what specifically discriminates a `.xzy` failure (a
            // physically-circular orbit reseeded from axis-swapped state vectors comes
            // out with non-zero apparent eccentricity). Tight bounds chosen from the
            // dynamically-built state vector: circular at 203 587 m gives
            // sma = 803 587 m and near-zero eccentricity/inclination. The velocity
            // is computed from the body's live transform so this test only catches
            // frame conversion regressions, not harmless body-rotation phase drift.
            InGameAssert.IsTrue(System.Math.Abs(semiMajorAxis - 803_587.0) < 5_000.0,
                $"sma={semiMajorAxis:F1} should be near 803 587 m (analytic circular at 203.587 km); " +
                "if this fails, the (pos - body.position) subtraction is wrong (|pos| went off by the body.position offset)");
            InGameAssert.IsTrue(eccentricity < 0.005,
                $"ecc={eccentricity:F4} should be near zero for a circular orbit; " +
                "if this fails specifically (and sma is right), the `.xzy` flip is missing on either pos or vel");
            // The synthetic vector is built tangent to Kerbin's equator at the current
            // body rotation, so inclination should stay near zero.
            InGameAssert.IsTrue(inclination >= 0.0 && inclination < 0.5,
                $"inclination={inclination:F4}° should be near zero for an equatorial state vector");

            ParsekLog.Info("TestRunner",
                $"TerminalOrbitFromTail_DerivesPostBurnCircularOrbit: " +
                $"sma={semiMajorAxis:F1} ecc={eccentricity:F4} " +
                $"periAlt={periAlt:F0} apoAlt={apoAlt:F0} safeAlt={safeAlt:F0} " +
                $"inc={inclination:F4} decision={decision.Action}");
        }

        [InGameTest(Category = "SpawnTerminalOrbit", Scene = GameScenes.FLIGHT,
            Description = "Probe-shape tail (highly eccentric ellipse) reseeds correctly — sma must match the analytic 4.5 Mm orbit, not the buggy ~500 k garbage that the bare UpdateFromStateVectors produces")]
        public void TerminalOrbitFromTail_DerivesPostBurnEccentricOrbit()
        {
            // Mirrors `logs/2026-05-10_2123` recording rec_f1363fc127ab47a28812ce4be6515453
            // (Kerbal X Probe Re-Fly fork) — terminal=Orbiting, tOrbSma=4 547 677,
            // tOrbEcc=0.822, periAlt ≈ 208 km. Without the (pos - body.position).xzy +
            // vel.xzy frame correction, `Orbit.UpdateFromStateVectors` produced
            // sma=567 357, periAlt=-438 km (subsurface) and the spawn was permanently
            // rejected. With the correction in OrbitReseed, sma must come out within
            // tight tolerance of the recording's stored tOrbSma.
            //
            // This is the regression test that pins the actual probe-spawn bug — the
            // prior near-circular test happened to clear the safety gate even under
            // the buggy frame, which is why the bug shipped. This high-eccentricity
            // case fails fast under the bug (periAlt sub-surface → CannotSpawnSafely)
            // and passes under the fix.
            CelestialBody kerbin = FlightGlobals.Bodies?.Find(b => b.bodyName == "Kerbin");
            if (kerbin == null)
            {
                InGameAssert.Skip("Kerbin not found in FlightGlobals.Bodies");
                return;
            }
            // The bug is most observable when `body.position` is non-trivially
            // offset from the world origin — that's when the missing
            // `(pos − body.position)` step corrupts sma. If the test happens to
            // run when Krakensbane has Kerbin sitting at the origin, the buggy
            // code would produce an accidentally-correct sma and the assertions
            // below would let the bug slip. Require a non-trivial offset
            // (|body.position|² > 1 km²) so the test reliably exercises the
            // frame-correction we care about, and skip with a clear reason
            // otherwise so the failure is observable rather than silent.
            if (kerbin.position.sqrMagnitude < 1_000_000.0)
            {
                InGameAssert.Skip($"Kerbin.position.sqrMagnitude={kerbin.position.sqrMagnitude:F1} too small to discriminate the body.position offset bug");
                return;
            }

            const double tailUT = 453.66214255408767;
            const double tailAlt = 208_283.22164018429;
            // Verbatim from the captured recording's last absolute coast frame.
            UnityEngine.Vector3 tailVel = new UnityEngine.Vector3(296.024567f, 3.8434844f, -2806.1167f);

            var rec = new Recording { RecordingId = "ingame-probe-tail-shape" };
            rec.OrbitSegments.Add(new OrbitSegment
            {
                bodyName = "Kerbin",
                startUT = 142.16,
                endUT = 415.02,
                inclination = 0.0977,
                eccentricity = 0.5746,
                semiMajorAxis = 512_941.0,    // pre-burn stale segment — not what we want spawn to use
                longitudeOfAscendingNode = 75.6,
                argumentOfPeriapsis = 342.3,
                meanAnomalyAtEpoch = 1.6818,
                epoch = 142.16
            });
            var coastSection = new TrackSection
            {
                environment = SegmentEnvironment.ExoBallistic,
                referenceFrame = ReferenceFrame.Absolute,
                startUT = 444.60214255409591,
                endUT = tailUT,
                frames = new System.Collections.Generic.List<TrajectoryPoint>
                {
                    new TrajectoryPoint
                    {
                        ut = tailUT,
                        latitude = -0.020555305204629719,
                        longitude = -36.664361532582674,
                        altitude = tailAlt,
                        rotation = UnityEngine.Quaternion.identity,
                        velocity = tailVel,
                        bodyName = "Kerbin"
                    }
                }
            };
            rec.TrackSections.Add(coastSection);

            // spawnUT == tailUT keeps the rotation-drift clamp at zero.
            bool helperOk = VesselSpawner.TryDeriveTerminalOrbitSeedFromTrajectoryTail(
                rec, kerbin, tailUT,
                out double inclination,
                out double eccentricity,
                out double semiMajorAxis,
                out double lan,
                out double argPe,
                out _, out _,
                out string bodyName,
                out string declineReason);

            InGameAssert.IsTrue(helperOk,
                $"TryDeriveTerminalOrbitSeedFromTrajectoryTail should succeed (declineReason={declineReason ?? "(null)"})");
            InGameAssert.AreEqual("Kerbin", bodyName);

            // Analytic check on the state vector:
            //   r = R + alt = 808 283 m
            //   v² = 296.02² + 3.84² + 2806.12² ≈ 7 961 267 m²/s²
            //   ε  = v²/2 − μ/r = 3.981×10⁶ − 4.370×10⁶ = −3.89×10⁵ m²/s²
            //   sma = −μ/(2ε) ≈ 4.54 × 10⁶ m
            // 50 km absolute tolerance leaves headroom for body-rotation drift between
            // the synthetic state vector and KSP's body.position evaluation, but is
            // tight enough to catch the bug's sma=567 357 (off by 4 Mm).
            InGameAssert.IsTrue(System.Math.Abs(semiMajorAxis - 4_540_000.0) < 50_000.0,
                $"sma={semiMajorAxis:F1} m should be near analytic 4.54 Mm; " +
                "if this fails near 567 k, the (pos - body.position).xzy + vel.xzy frame correction is missing");
            InGameAssert.IsTrue(eccentricity > 0.80 && eccentricity < 0.84,
                $"ecc={eccentricity:F4} should be near 0.822 (recording's tOrbEcc); got value indicates a wrong-magnitude reseed");

            // Periapsis altitude must clear safe altitude. Under the bug this came out
            // at -438 km (subsurface) and the safety gate rejected.
            double periAlt = semiMajorAxis * (1.0 - eccentricity) - kerbin.Radius;
            double safeAlt = TerminalOrbitSpawnSafety.ComputeSafeAltitude(
                kerbin.atmosphereDepth, TerminalOrbitSpawnSafety.DefaultSafetyMarginMeters);
            InGameAssert.IsTrue(periAlt > safeAlt,
                $"Derived periapsis ({periAlt:F0} m) must clear safe altitude ({safeAlt:F0} m); " +
                "this is the user-visible spawn-safety bug repro");

            ParsekLog.Info("TestRunner",
                $"TerminalOrbitFromTail_DerivesPostBurnEccentricOrbit: " +
                $"sma={semiMajorAxis:F1} ecc={eccentricity:F4} inc={inclination:F4} " +
                $"lan={lan:F2} argPe={argPe:F2} periAlt={periAlt:F0} safeAlt={safeAlt:F0}");
        }

        [InGameTest(Category = "GhostMap", Scene = GameScenes.FLIGHT,
            Description = "Map-presence endpoint-tail seed accepts large activation-to-tail UT gaps only through historical body-relative reconstruction")]
        public void GhostMapEndpointTail_UsesHistoricalTailSeedAcrossActivationDrift()
        {
            CelestialBody kerbin = FlightGlobals.Bodies?.Find(b => b.bodyName == "Kerbin");
            if (kerbin == null)
            {
                InGameAssert.Skip("Kerbin not found in FlightGlobals.Bodies");
                return;
            }

            const double activationUT = 135.7;
            const double tailUT = 453.66214255408767;
            var rec = new Recording
            {
                RecordingId = "ingame-endpoint-tail-map-presence",
                VesselName = "Endpoint tail map presence",
                ExplicitStartUT = 100.0,
                ExplicitEndUT = 600.0,
                TerminalStateValue = TerminalState.Orbiting,
                TerminalOrbitBody = "Kerbin",
                TerminalOrbitSemiMajorAxis = 4_547_677.0,
                TerminalOrbitEccentricity = 0.822,
                EndpointPhase = RecordingEndpointPhase.OrbitSegment,
                EndpointBodyName = "Kerbin",
                Points = new System.Collections.Generic.List<TrajectoryPoint>
                {
                    new TrajectoryPoint
                    {
                        ut = tailUT,
                        bodyName = "Kerbin",
                        altitude = 208_283.22164018429,
                        velocity = new UnityEngine.Vector3(296.024567f, 3.8434844f, -2806.1167f)
                    }
                },
                OrbitSegments = new System.Collections.Generic.List<OrbitSegment>
                {
                    new OrbitSegment
                    {
                        bodyName = "Kerbin",
                        startUT = 120.0,
                        endUT = 150.0,
                        semiMajorAxis = 512_941.0,
                        eccentricity = 0.5746,
                        inclination = 0.0977,
                        longitudeOfAscendingNode = 75.6,
                        argumentOfPeriapsis = 342.3,
                        meanAnomalyAtEpoch = 1.6818,
                        epoch = 120.0
                    }
                },
                TrackSections = new System.Collections.Generic.List<TrackSection>
                {
                    new TrackSection
                    {
                        environment = SegmentEnvironment.ExoBallistic,
                        referenceFrame = ReferenceFrame.Absolute,
                        startUT = 444.60214255409591,
                        endUT = tailUT,
                        frames = new System.Collections.Generic.List<TrajectoryPoint>
                        {
                            new TrajectoryPoint
                            {
                                ut = tailUT,
                                latitude = -0.020555305204629719,
                                longitude = -36.664361532582674,
                                altitude = 208_283.22164018429,
                                rotation = UnityEngine.Quaternion.identity,
                                velocity = new UnityEngine.Vector3(296.024567f, 3.8434844f, -2806.1167f),
                                bodyName = "Kerbin"
                            }
                        }
                    }
                }
            };

            bool seedOk = OrbitSeedResolver.TryDeriveTailOrbitSeed(
                rec,
                kerbin,
                activationUT,
                TailSeedUse.MapPresence,
                out TailDerivedOrbitSeed seed);
            InGameAssert.IsTrue(seedOk,
                $"MapPresence tail seed should succeed via historical rotation (decline={seed.DeclineReason ?? "(none)"})");
            InGameAssert.IsTrue(seed.UsedHistoricalBodyRotation,
                "MapPresence tail seed must use the historical body-relative path");
            InGameAssert.IsTrue(System.Math.Abs(seed.RotationDriftSeconds) > VesselSpawner.TailDerivedOrbitMaxRotationDriftSeconds,
                $"Test must exercise drift above spawn guard; drift={seed.RotationDriftSeconds:F2}s");
            InGameAssert.IsTrue(seed.Segment.semiMajorAxis > 0.0 && seed.Segment.eccentricity >= 0.0,
                $"EndpointTail segment should be finite positive orbit data; sma={seed.Segment.semiMajorAxis:F1} ecc={seed.Segment.eccentricity:F4}");

            int cached = -1;
            GhostMapPresence.TrackingStationGhostSource source =
                GhostMapPresence.ResolveMapPresenceGhostSource(
                    rec,
                    isSuppressed: false,
                    alreadyMaterialized: false,
                    currentUT: activationUT,
                    allowTerminalOrbitFallback: true,
                    logOperationName: "ingame-endpoint-tail-map",
                    ref cached,
                    out OrbitSegment resolvedSegment,
                    out _,
                    out string skipReason);
            InGameAssert.AreEqual(
                GhostMapPresence.TrackingStationGhostSource.EndpointTail,
                source,
                $"Map source should be EndpointTail, got {source} skip={skipReason ?? "(none)"}");
            InGameAssert.ApproxEqual(tailUT, resolvedSegment.epoch, 1e-6);

            ParsekLog.Info("TestRunner",
                $"GhostMapEndpointTail_UsesHistoricalTailSeedAcrossActivationDrift: " +
                $"drift={seed.RotationDriftSeconds:F2}s sma={seed.Segment.semiMajorAxis:F1} " +
                $"ecc={seed.Segment.eccentricity:F4} source={source}");
        }

        /// <summary>
        /// Frozen-icon-on-short-arc fix (flight map): the ghost icon position is propagated at the
        /// loop-mapped effUT each frame (GhostOrbitIconDrivePatch), so it must GLIDE continuously
        /// along a SUB-PERIOD orbital arc even while the live clock would barely advance through the
        /// thin recorded window. Uses a real KSP Orbit with the exact frozen-icon segment elements
        /// (sma=671928 ecc=0.0883 near Kerbin, a ~80 deg arc) and asserts the propagated world
        /// position advances > 1 m per effUT step (status=moving), then stays continuous when effUT
        /// crosses the recorded segment endpoint into the next sample (no seam teleport in effUT
        /// space). This is a Unity-runtime check of the PREMISE the fix relies on (a sub-period arc's
        /// Kepler position is a continuous function of effUT, which xUnit cannot evaluate since it
        /// cannot run Orbit.UpdateFromUT). It does NOT fire the live GhostOrbitIconDrivePatch on a real
        /// ghost ProtoVessel: the patch decision logic is covered by GhostOrbitIconDriveTests, and the
        /// end-to-end behaviour by playtest.
        /// </summary>
        [InGameTest(Category = "GhostMap", Scene = GameScenes.FLIGHT,
            Description = "Ghost map icon glides along a sub-period orbital arc when driven at effUT (no freeze/seam)")]
        public void GhostMapIconGlidesOnShortArc_Flight()
        {
            AssertIconGlidesOnShortArc("FLIGHT");
        }

        /// <summary>
        /// Tracking-Station variant of <see cref="GhostMapIconGlidesOnShortArc_Flight"/>: the same
        /// premise check, run under the TRACKSTATION scene tag. It shares AssertIconGlidesOnShortArc and
        /// differs from the flight variant only by scene, so it confirms the Kepler premise holds in the
        /// TS runtime, not that the live patch fires there. Scene parity of the actual fix is by
        /// construction (the patch is keyed only on IsGhostMapVessel with no scene check, and the TS
        /// refresh feeds the SAME segment + loop shift through the SAME ApplyOrbitToVessel) plus playtest.
        /// </summary>
        [InGameTest(Category = "GhostMap", Scene = GameScenes.TRACKSTATION,
            Description = "Ghost map icon glides along a sub-period orbital arc in the Tracking Station too")]
        public void GhostMapIconGlidesOnShortArc_TrackingStation()
        {
            AssertIconGlidesOnShortArc("TRACKSTATION");
        }

        private static void AssertIconGlidesOnShortArc(string scene)
        {
            CelestialBody kerbin = FlightGlobals.Bodies?.Find(b => b.bodyName == "Kerbin");
            if (kerbin == null)
            {
                InGameAssert.Skip("Kerbin not found in FlightGlobals.Bodies");
                return;
            }

            // The exact frozen-icon segment from the evidence log (rec 61e9...30 "Kerbal X"):
            // sma=671928 ecc=0.0883, recorded window 52569494.7..52569925.6 (~431 s) = a ~80 deg arc
            // of the ~1842 s orbit. Raw epoch (no shift baked in), matching ApplyOrbitToVessel.
            var orbit = new Orbit();
            orbit.referenceBody = kerbin;
            const double rawEpoch = 52569494.7;
            const double rawStart = 52569494.7;
            const double rawEnd = 52569925.6;
            orbit.SetOrbit(0.1887, 0.088283, 671928.0, 75.0, 152.9042, 1.463204, rawEpoch, kerbin);
            orbit.Init();

            // The fix drives the OrbitDriver at effUT = liveUT - shift. effUT advances 1:1 with the
            // loop clock; sample it at five points spanning the recorded window and assert the
            // propagated position advances every step (the icon glides, not freezes).
            const int steps = 5;
            double prevDist = double.NaN;
            Vector3d prevPos = Vector3d.zero;
            double minStep = double.MaxValue;
            double maxStep = 0.0;
            for (int i = 0; i < steps; i++)
            {
                double effUT = rawStart + (rawEnd - rawStart) * (i / (double)(steps - 1));
                orbit.UpdateFromUT(effUT);
                Vector3d pos = orbit.pos;
                if (i > 0)
                {
                    double step = (pos - prevPos).magnitude;
                    minStep = System.Math.Min(minStep, step);
                    maxStep = System.Math.Max(maxStep, step);
                }
                prevPos = pos;
                prevDist = pos.magnitude;
            }

            InGameAssert.IsGreaterThan(minStep, 1.0,
                $"[{scene}] icon must advance > 1 m per effUT step on the short arc " +
                $"(minStep={minStep:F1} m) — a frozen icon would step ~0 m");

            // Seam continuity: stepping one effUT increment PAST the recorded end must move by a
            // comparable amount, not teleport. The icon is a continuous function of effUT, so the
            // cross-endpoint step should be the same order of magnitude as the in-window steps.
            double dt = (rawEnd - rawStart) / (steps - 1);
            orbit.UpdateFromUT(rawEnd);
            Vector3d atEnd = orbit.pos;
            orbit.UpdateFromUT(rawEnd + dt);
            Vector3d pastEnd = orbit.pos;
            double seamStep = (pastEnd - atEnd).magnitude;
            InGameAssert.IsGreaterThan(seamStep, 1.0,
                $"[{scene}] icon must keep moving across the segment endpoint (seamStep={seamStep:F1} m)");
            InGameAssert.IsLessThan(seamStep, maxStep * 5.0,
                $"[{scene}] cross-endpoint step ({seamStep:F1} m) must be the same order as in-window " +
                $"steps (maxStep={maxStep:F1} m) — no seam teleport");

            // Sanity: the elements are sub-period (the arc is genuinely a sliver of the orbit), so
            // this is the freeze-prone regime the fix targets.
            double windowFraction = (rawEnd - rawStart) / orbit.period;
            InGameAssert.IsLessThan(windowFraction, 1.0,
                $"[{scene}] test must use a sub-period arc (window={windowFraction:F3} of period {orbit.period:F0}s)");

            ParsekLog.Info("TestRunner",
                $"GhostMapIconGlidesOnShortArc[{scene}]: period={orbit.period:F0}s " +
                $"windowFrac={windowFraction:F3} minStep={minStep:F1}m maxStep={maxStep:F1}m " +
                $"seamStep={seamStep:F1}m");
        }

        /// <summary>
        /// Director-drive (Phase 8a) epoch-bake fix for the looped-re-aim icon-off-orbit bug. KSP
        /// resolves a packed map ghost's icon world position by re-propagating its orbit at the LIVE
        /// Planetarium clock (CoMD = referenceBody.position + orbitDriver.pos, rebuilt every
        /// FixedUpdate), so the legacy raw-epoch orbit drawn for the LINE renders the ICON at the live
        /// phase - ~96.5 deg off the recorded arc on the failing mission. <see cref="StockConicTreatment.SeedAndDriveLive"/>
        /// bakes the loop shift into the EPOCH so that LIVE-clock resolution lands on the SAME recorded
        /// phase the line is drawn from. This is the Unity-runtime guard the xUnit pure tests cannot be
        /// (it runs a REAL KSP Orbit.SetOrbit / UpdateFromUT). Uses the exact "Kerbal X Probe" elliptical
        /// Kerbin orbit + the huge live/recorded clock gap from the s15 "Duna One" evidence log.
        /// </summary>
        [InGameTest(Category = "GhostMap", Scene = GameScenes.FLIGHT,
            Description = "Director-drive epoch-bake places the ghost icon on its recorded orbit phase at the live clock (icon-off-orbit fix)")]
        public void DirectorDriveEpochBakePlacesIconOnRecordedPhase()
        {
            CelestialBody kerbin = FlightGlobals.Bodies?.Find(b => b.bodyName == "Kerbin");
            if (kerbin == null)
            {
                InGameAssert.Skip("Kerbin not found in FlightGlobals.Bodies");
                return;
            }

            // The "Kerbal X Probe" elliptical Kerbin orbit from the icon-off-orbit evidence log.
            const double rawEpoch = 52569494.7;
            var seg = new OrbitSegment
            {
                inclination = 0.1887,
                eccentricity = 0.088283,
                semiMajorAxis = 671928.0,
                longitudeOfAscendingNode = 75.0,
                argumentOfPeriapsis = 152.9042,
                meanAnomalyAtEpoch = 1.463204,
                epoch = rawEpoch,
                bodyName = "Kerbin",
                startUT = 52569494.7,
                endUT = 52569925.6,
            };

            // The huge loop shift from the evidence: live clock ~1.40e9, recorded effUT ~6.40e7.
            const double liveUT = 1400335935.057;
            const double effUT = 63964105.314;
            double shift = liveUT - effUT;

            // REFERENCE: the recorded phase = the raw-epoch orbit at effUT (what the LINE is drawn from).
            var rawOrbit = new Orbit { referenceBody = kerbin };
            Parsek.MapRender.StockConicTreatment.SeedAndDrive(rawOrbit, seg, kerbin, effUT);
            rawOrbit.Init();
            rawOrbit.UpdateFromUT(effUT);
            double recordedTrueAnomaly = rawOrbit.trueAnomaly; // frame-invariant phase the LINE is drawn from

            // FIX: SeedAndDriveLive bakes epoch+shift; the LIVE-clock resolution (how KSP rebuilds the
            // packed icon position) must land on the SAME recorded phase.
            var bakedOrbit = new Orbit { referenceBody = kerbin };
            Parsek.MapRender.StockConicTreatment.SeedAndDriveLive(bakedOrbit, seg, kerbin, shift, liveUT);
            bakedOrbit.Init();
            bakedOrbit.UpdateFromUT(liveUT);
            double bakedTrueAnomaly = bakedOrbit.trueAnomaly; // epoch-baked phase resolved at the LIVE clock

            // BUG CONTRAST: the raw-epoch orbit resolved at the LIVE clock (the pre-fix phase) lands on a
            // DIFFERENT orbital phase than the recorded effUT phase.
            double buggyTrueAnomaly = rawOrbit.TrueAnomalyAtUT(liveUT);

            // Frame-invariant phase deltas (degrees, wrapped to [0,180]). World-position comparison is
            // unusable here: UpdateFromUT emits pos in the body's ROTATING Zup frame at the sample UT, so
            // sampling at liveUT vs effUT (a ~1.336e9 s loop shift) projects identical phases into frames
            // separated by Kerbin's rotation (~96.5 deg). The true anomaly the epoch-bake controls is the
            // correct, frame-free invariant.
            double fixPhaseDiffDeg = AnglePhaseDiffDeg(bakedTrueAnomaly, recordedTrueAnomaly);
            double buggyPhaseDiffDeg = AnglePhaseDiffDeg(buggyTrueAnomaly, recordedTrueAnomaly);

            InGameAssert.IsLessThan(fixPhaseDiffDeg, 0.1,
                $"epoch-bake icon must sit on the recorded orbital phase at the live clock " +
                $"(true-anomaly diff={fixPhaseDiffDeg:F4} deg)");
            InGameAssert.IsGreaterThan(buggyPhaseDiffDeg, 1.0,
                $"sanity: the raw-epoch-at-live phase (the bug) must be off the recorded phase " +
                $"(true-anomaly diff={buggyPhaseDiffDeg:F2} deg) - else the test orbit/shift is degenerate");

            ParsekLog.Info("TestRunner",
                $"DirectorDriveEpochBake: shift={shift:F0}s fixPhaseDiff={fixPhaseDiffDeg:F4}deg " +
                $"buggyPhaseDiff={buggyPhaseDiffDeg:F2}deg");
        }

        // Smallest absolute difference between two true anomalies (radians), wrapped into [0,180] degrees.
        private static double AnglePhaseDiffDeg(double aRad, double bRad)
        {
            double d = (aRad - bRad) % (2.0 * System.Math.PI);
            if (d < 0.0) d += 2.0 * System.Math.PI;          // [0, 2pi)
            if (d > System.Math.PI) d = 2.0 * System.Math.PI - d; // fold to [0, pi]
            return d * (180.0 / System.Math.PI);
        }

        /// <summary>
        /// Parking -> loiter orbit-RAISE gap glide (flight map). When the playback head is in the
        /// ~205 s raise gap between the parking segment (sma 671928) and the loiter segment (sma
        /// 731230), the dispatcher routes the icon onto the recorded body-fixed POINTS via
        /// <see cref="GhostMapPresence.UpdateGhostOrbitFromStateVectors"/>, which resolves world
        /// position through <c>CelestialBody.GetWorldSurfacePosition(lat, lon, alt)</c>. The bug
        /// instead carried the stale parking OrbitSegment forward, freezing the icon and teleporting
        /// it ~1318 km onto the loiter orbit at the seam.
        ///
        /// This is the Unity-runtime integration guard the xUnit predicate/continuity test cannot
        /// be: it projects the recorded gap points through the REAL Kerbin
        /// <c>GetWorldSurfacePosition</c> (the exact resolution the live dispatcher uses) and a REAL
        /// KSP <see cref="Orbit"/> for the carried parking segment (the buggy carry), then asserts
        /// the points-driven world track glides (max step &lt; 50 km) while the carry track exhibits
        /// the &gt; 100 km teleport. xUnit cannot run either GetWorldSurfacePosition or
        /// Orbit.UpdateFromUT. It does NOT spawn a live ghost ProtoVessel (that requires the full
        /// materialization path); the dispatcher decision is covered by GhostMapOrbitRaiseGapTests
        /// (predicate) and the end-to-end behaviour by playtest.
        /// </summary>
        [InGameTest(Category = "GhostMap", Scene = GameScenes.FLIGHT,
            Description = "Ghost map icon glides the recorded ascent across a parking->loiter raise gap (no freeze/teleport)")]
        public void GhostMapIconGlidesAcrossRaiseGap_Flight()
        {
            AssertIconGlidesAcrossRaiseGap("FLIGHT");
        }

        /// <summary>
        /// Tracking-Station variant of <see cref="GhostMapIconGlidesAcrossRaiseGap_Flight"/>. The TS
        /// dispatcher (GhostMapPresence.RefreshTrackingStationGhosts) routes the gap glide through the
        /// SAME ShouldDriveGapFromPoints predicate and the SAME GetWorldSurfacePosition resolution as
        /// the flight scene, so the world-position continuity holds identically in the TS runtime.
        /// </summary>
        [InGameTest(Category = "GhostMap", Scene = GameScenes.TRACKSTATION,
            Description = "Ghost map icon glides the recorded ascent across a parking->loiter raise gap in the Tracking Station too")]
        public void GhostMapIconGlidesAcrossRaiseGap_TrackingStation()
        {
            AssertIconGlidesAcrossRaiseGap("TRACKSTATION");
        }

        private static void AssertIconGlidesAcrossRaiseGap(string scene)
        {
            CelestialBody kerbin = FlightGlobals.Bodies?.Find(b => b.bodyName == "Kerbin");
            if (kerbin == null)
            {
                InGameAssert.Skip("Kerbin not found in FlightGlobals.Bodies");
                return;
            }

            // Recorded structure from rec 61e9177193444e329247d0e8288cf91e (the raise gap):
            // parking seg ends at 52569969.49, loiter seg starts at 52570174.17 (a ~205 s gap with
            // NO covering OrbitSegment but ~84 body-fixed Absolute points at ~131 km).
            const double parkingEndUT = 52569969.494702443;
            const double loiterStartUT = 52570174.174735993;

            // (a) FIXED path: drive the icon from the recorded body-fixed points, resolved through the
            // REAL Kerbin GetWorldSurfacePosition (the exact call UpdateGhostOrbitFromStateVectors makes
            // for an Absolute point). Sample lat/lon/alt along the recorded ascent at ~5 s cadence.
            const int steps = 41;
            double maxFixedStep = 0.0;
            Vector3d prevFixed = Vector3d.zero;
            for (int i = 0; i < steps; i++)
            {
                double f = i / (double)(steps - 1);
                double lat = -0.0940870293026434 + f * (0.01735396213266869 - (-0.0940870293026434));
                double lon = 33.33922852313182 + f * (65.0419383682048 - 33.33922852313182);
                double alt = 131165.32404627802 + f * (131764.85360325896 - 131165.32404627802);
                Vector3d pos = kerbin.GetWorldSurfacePosition(lat, lon, alt);
                if (i > 0)
                {
                    double step = (pos - prevFixed).magnitude;
                    if (step > maxFixedStep) maxFixedStep = step;
                }
                prevFixed = pos;
            }

            InGameAssert.IsLessThan(maxFixedStep, 50000.0,
                $"[{scene}] points-driven icon must glide the raise arc continuously " +
                $"(max step {maxFixedStep:F0} m, expected < 50 km) — the world-position resolution the fix routes through");

            // (b) BUGGY carry path: the parking OrbitSegment is carried across the whole gap (icon
            // pinned at the parking-orbit phase at parkingEndUT) and then snaps to the loiter orbit at
            // loiterStartUT. Use a REAL KSP Orbit for each and measure the seam jump.
            var parking = new Orbit();
            parking.referenceBody = kerbin;
            parking.SetOrbit(0.18870260431072694, 0.088283234082374554, 671928.40970866173,
                335.69895266376579, 152.90421069401148, 1.463204, 52569494.7, kerbin);
            parking.Init();
            parking.UpdateFromUT(parkingEndUT);
            Vector3d carriedParkingPos = parking.pos;

            var loiter = new Orbit();
            loiter.referenceBody = kerbin;
            loiter.SetOrbit(0.18903449190718044, 0.0013137142817968353, 731229.57633187377,
                335.64572740348439, 241.34144799953822, 1.463204, loiterStartUT, kerbin);
            loiter.Init();
            loiter.UpdateFromUT(loiterStartUT);
            Vector3d loiterEntryPos = loiter.pos;

            double seamJump = (loiterEntryPos - carriedParkingPos).magnitude;
            InGameAssert.IsGreaterThan(seamJump, 50000.0,
                $"[{scene}] the buggy same-body carry must teleport across the gap " +
                $"(seam jump {seamJump:F0} m, expected > 50 km) - if this fails the regression model is stale");

            InGameAssert.IsTrue(maxFixedStep * 4 < seamJump,
                $"[{scene}] the points-driven glide step ({maxFixedStep:F0} m) must be far smaller than the " +
                $"carry seam ({seamJump:F0} m) - the fix removes the teleport");

            ParsekLog.Info("TestRunner",
                $"GhostMapIconGlidesAcrossRaiseGap[{scene}]: maxFixedStep={maxFixedStep:F0}m seamJump={seamJump:F0}m");
        }

        /// <summary>
        /// Inertial-frame gap glide under a large loop shift (the ~90 deg icon-teleport fix). On a
        /// LOOPED re-aimed mission the gap point is replayed ~1e9 s after it was recorded; Kerbin has
        /// rotated ~96.6 deg over that shift. The body-fixed seed (the pre-fix path) resolves the gap
        /// point via <c>GetWorldSurfacePosition</c> at the LIVE Kerbin orientation, so the icon sits
        /// rotated off the inertial orbit lines (drawn from recorded Keplerian elements). The fix
        /// (<see cref="OrbitReseed.TryFromHistoricalLatLonAltAndRecordedVelocityWithEpoch"/>)
        /// reconstructs the point's INERTIAL position from its recorded UT + body rotation (incl.
        /// initialRotation) and seeds the orbit at the loop-shifted epoch, so the seeded orbit's
        /// position at liveUT matches the recorded INERTIAL longitude, not the live-BodyFrame
        /// body-fixed projection.
        ///
        /// This is the only path that exercises the live <c>body.rotationPeriod</c> +
        /// <c>initialRotation</c> + <c>GetRelSurfacePosition</c> + <c>Orbit.UpdateFromStateVectors</c>
        /// together (xUnit cannot run any of those). It asserts: (a) the inertial seed succeeds;
        /// (b) OrbitReseed reconstructs the inertial longitude as lon lifted by the recorded rotation
        /// phase (initialRotation + recordedUT * 360 / period) -- this is the regression guard: it fails
        /// if the seed mis-reconstructs the inertial longitude; (c) the live-BodyFrame body-fixed
        /// projection of the same gap point sits far (more than 100 km) off the recorded inertial line
        /// point, the ~90 deg teleport the inertial reconstruction removes.
        /// NOTE: this does NOT magnitude-compare the seeded orbit's world position against the recorded
        /// inertial line point. Those two quantities live in different KSP frames: the orbit's pos is
        /// seeded in the static <c>Planetarium.Zup</c> world frame by <c>Orbit.UpdateFromStateVectors</c>
        /// and read back through <c>ZupAtT(epochUT)</c> (a ~187.9 deg loop-shifted rotation for Kerbin),
        /// while the line point is a frameless <c>GetRelSurfacePosition</c> spherical vector carrying no
        /// Zup/ZupAtT rotation. A magnitude comparison between them is a frame-mismatch artifact (~1.29 Mm
        /// on a 731 km orbit), not a co-location proof. True icon-on-line co-location is a playtest
        /// concern; the longitude-reconstruction assert below is the frame-clean regression guard.
        /// </summary>
        [InGameTest(Category = "GhostMap", Scene = GameScenes.FLIGHT,
            Description = "Looped gap glide seeds the recorded inertial position (icon stays on the orbit lines, no ~90 deg teleport)")]
        public void GhostMapGapGlideSeedsInertialPositionUnderLoopShift()
        {
            CelestialBody kerbin = FlightGlobals.Bodies?.Find(b => b.bodyName == "Kerbin");
            if (kerbin == null)
            {
                InGameAssert.Skip("Kerbin not found in FlightGlobals.Bodies");
                return;
            }

            // A mid-gap point from the recorded raise arc (rec 61e9...30): body-fixed lat/lon/alt at
            // ~131 km, recorded UT inside the parking->loiter gap, and a typical ~2.1 km/s velocity.
            const double recordedUT = 52570071.0;        // mid-gap
            const double lat = -0.0383;
            const double lon = 49.19;                     // body-fixed longitude as recorded
            const double alt = 131465.0;
            var recordedVel = new Vector3d(2100.0, 0.0, 0.0);

            // The loop replays ~1.002e9 s later (the Kerbin->Duna loop period from the evidence log).
            const double loopShift = 1.002e9;
            double epochUT = recordedUT + loopShift;

            double rotationPeriod = kerbin.rotationPeriod;
            InGameAssert.IsTrue(!double.IsNaN(rotationPeriod) && System.Math.Abs(rotationPeriod) > 1.0,
                $"Kerbin rotationPeriod must be finite/non-zero (got {rotationPeriod:F1})");

            // Resolve initialRotation via the same reflection path the chokepoint uses.
            double initialRotation = OrbitSeedResolver.ResolveInitialRotation(kerbin);

            // (a) The FIX: reconstruct the inertial position at the recorded UT, seed the orbit at the
            // loop-shifted epoch. This is the EXACT call UpdateGhostOrbitFromStateVectors makes for the
            // orbit-raise-gap-points reason on an Absolute branch.
            var inertialOrbit = new Orbit();
            inertialOrbit.referenceBody = kerbin;
            bool inertialOk = OrbitReseed.TryFromHistoricalLatLonAltAndRecordedVelocityWithEpoch(
                inertialOrbit, kerbin, lat, lon, alt, recordedVel,
                recordedUT, epochUT, rotationPeriod, initialRotation,
                out double inertialLon, out string inertialFail);
            InGameAssert.IsTrue(inertialOk,
                $"inertial seed must succeed (fail={inertialFail ?? "(null)"})");

            // Propagate the seeded orbit to liveUT (== epochUT) to confirm the seed yields a finite,
            // physically-valid orbit (no NaN elements). The resulting orbit.pos lives in the
            // ZupAtT(epochUT) readout frame, so it is NOT magnitude-compared against the frameless
            // recorded inertial line point below (see the method doc for why that comparison would be a
            // frame-mismatch artifact); the longitude-reconstruction assert is the frame-clean guard.
            inertialOrbit.Init();
            inertialOrbit.UpdateFromUT(epochUT);
            Vector3d inertialIconWorld = kerbin.position + inertialOrbit.pos;   // body-relative -> world
            InGameAssert.IsTrue(
                !double.IsNaN(inertialIconWorld.x) && !double.IsNaN(inertialIconWorld.y)
                    && !double.IsNaN(inertialIconWorld.z),
                "seeded inertial orbit must propagate to a finite world position at the loop-shifted epoch");

            // The recorded INERTIAL world position the orbit LINES draw from: a body-relative point at
            // the recorded rotation phase (lon lifted by initialRotation + recordedUT * 360 / period).
            double phaseDeg = initialRotation + (recordedUT * 360.0) / rotationPeriod;
            double recordedInertialLon = OrbitReseed.WrapLongitudeDegrees(lon + phaseDeg);
            InGameAssert.IsTrue(System.Math.Abs(recordedInertialLon - inertialLon) < 1e-3,
                $"reconstructed inertial longitude ({inertialLon:F4}) must equal the recorded rotation-phase " +
                $"longitude ({recordedInertialLon:F4})");
            Vector3d recordedInertialWorld =
                kerbin.position + kerbin.GetRelSurfacePosition(lat, recordedInertialLon, alt);

            // (c) The BUG: the body-fixed seed projects the gap point through GetWorldSurfacePosition at
            // the LIVE Kerbin orientation. Over the ~1e9 s loop shift Kerbin rotated ~96.6 deg, so the
            // body-fixed icon sits that far around the orbit from the inertial line point. Show the
            // separation is large (the teleport the fix removes). Both terms here are body-relative
            // world offsets (live BodyFrame vs the recorded inertial line point), so the magnitude is a
            // meaningful "how far did the live-rotation seed wander off the recorded inertial geometry"
            // statement. The inertial-seed orbit's pos is NOT compared against this line point: that
            // orbit pos lives in the ZupAtT(epochUT) readout frame (see the method doc), so the seeded
            // icon's exact co-location with the line is left to playtest, not asserted by magnitude.
            Vector3d bodyFixedWorld = kerbin.GetWorldSurfacePosition(lat, lon, alt);
            double bodyFixedVsLine = (bodyFixedWorld - recordedInertialWorld).magnitude;
            InGameAssert.IsGreaterThan(bodyFixedVsLine, 100000.0,
                $"the body-fixed seed ({bodyFixedVsLine:F0} m from the inertial line point) must be far off " +
                $"the inertial line (the ~90 deg teleport): if this fails the loop-shift regression model is stale");

            ParsekLog.Info("TestRunner",
                $"GhostMapGapGlideSeedsInertialPositionUnderLoopShift: inertialLon={inertialLon:F2} " +
                $"recordedInertialLon={recordedInertialLon:F2} bodyFixedVsLine={bodyFixedVsLine:F0}m " +
                $"rotPeriod={rotationPeriod:F0}s initialRot={initialRotation:F2}");
        }

        /// <summary>
        /// Regression guard for the hyperbolic-escape ghost icon. The ghost OrbitDriver is seeded at the
        /// RAW recorded epoch (no loop shift baked in) and the icon-drive patch propagates it at the
        /// loop-mapped effUT. A hyperbolic escape segment (the Kerbin-SOI exit to interplanetary space)
        /// must be driven at effUT just like an ellipse: propagating it at the LIVE clock instead
        /// (liveUT = effUT + a ~1e9 s shift, far past the recorded escape) flings the icon billions of
        /// metres into deep space, off its trajectory (the "icon not rendered on the hyperbolic escape"
        /// regression). This uses the real escape orbit from the evidence log (rec 61e9...30 "Kerbal X",
        /// segment 63966985.6..64044032.7, sma=-3818300 ecc=1.1916). Drives at effUT across the segment
        /// window and asserts the position stays within Kerbin's SOI and advances; then shows that the
        /// live-UT (defer-to-stock) propagation lands orders of magnitude outside the SOI.
        /// </summary>
        [InGameTest(Category = "GhostPlayback",
            Description = "Hyperbolic escape ghost icon is driven at effUT (stays in SOI), not at live UT (deep space)",
            Scene = GameScenes.FLIGHT)]
        public void GhostMapIconDrivesHyperbolicEscapeAtEffUT()
        {
            CelestialBody kerbin = FlightGlobals.Bodies?.Find(b => b.bodyName == "Kerbin");
            if (kerbin == null)
            {
                InGameAssert.Skip("Kerbin not found in FlightGlobals.Bodies");
                return;
            }
            const double rawEpoch = 63966985.6;
            const double segStart = 63966985.6;
            const double segEnd = 64044032.7;
            var orbit = new Orbit();
            orbit.SetOrbit(1.3329, 1.1916, -3818300.0, 50.0, 60.0, 0.0238, rawEpoch, kerbin);
            orbit.Init();
            InGameAssert.IsTrue(orbit.eccentricity >= 1.0,
                $"test orbit must be hyperbolic (ecc={orbit.eccentricity:F3})");

            double soi = kerbin.sphereOfInfluence; // ~8.4e7 m for Kerbin
            // Drive at effUT across the recorded escape window: position must stay within the SOI
            // (the escape is inside Kerbin's SOI until segEnd) and advance every step (glides).
            const int steps = 6;
            Vector3d prev = Vector3d.zero;
            double minStep = double.MaxValue, maxInSoi = 0.0;
            for (int i = 0; i < steps; i++)
            {
                double effUT = segStart + (segEnd - segStart) * (i / (double)(steps - 1));
                orbit.UpdateFromUT(effUT);
                Vector3d pos = orbit.pos;
                InGameAssert.IsFalse(double.IsNaN(pos.x) || double.IsInfinity(pos.x),
                    $"effUT drive must produce a finite position (effUT={effUT:F0})");
                double r = pos.magnitude;
                maxInSoi = System.Math.Max(maxInSoi, r);
                // Allow a little margin past the SOI radius for the final exit sample.
                InGameAssert.IsLessThan(r, soi * 1.2,
                    $"effUT-driven escape must stay within Kerbin SOI (r={r:F0} m, SOI={soi:F0} m) — " +
                    $"a far-out position is the live-UT regression");
                if (i > 0) minStep = System.Math.Min(minStep, (pos - prev).magnitude);
                prev = pos;
            }
            InGameAssert.IsGreaterThan(minStep, 1.0,
                $"hyperbolic escape icon must advance > 1 m per effUT step (minStep={minStep:F1} m)");

            // Contrast: propagating at a LIVE-UT-like time (raw epoch + a representative ~8e8 s loop
            // shift = where stock would put it if the patch deferred) lands far outside the SOI. This
            // is the broken position the regression produced; the effUT drive above avoids it.
            orbit.UpdateFromUT(rawEpoch + 800000000.0);
            double rLiveUt = orbit.pos.magnitude;
            InGameAssert.IsGreaterThan(rLiveUt, soi * 100.0,
                $"sanity: live-UT propagation must land far outside the SOI (r={rLiveUt:F0} m, SOI={soi:F0} m) — " +
                $"this is exactly the deep-space misplacement the effUT drive prevents");

            ParsekLog.Info("TestRunner",
                $"GhostMapIconDrivesHyperbolicEscapeAtEffUT: SOI={soi:F0}m maxInWindow={maxInSoi:F0}m " +
                $"minStep={minStep:F1}m liveUtR={rLiveUt:E2}m");
        }

        /// <summary>
        /// Regression guard for the hyperbolic-escape ghost orbit LINE clip (Phase-8a coverage-gap
        /// Category 1). The icon already rode the hyperbola correctly; this asserts the LINE is
        /// clipped to its recorded segment window instead of being drawn by stock as the FULL open
        /// asymptote-to-asymptote hyperbola across the whole map. It replicates the exact computation
        /// <c>GhostOrbitArcPatch.Prefix</c> runs on a hyperbolic orbit (the patch's full
        /// OrbitRendererBase + ghostOrbitBounds plumbing is too heavy to wire up here, so this drives
        /// the real KSP Orbit anomaly/position helpers the clip depends on, like
        /// <see cref="DirectorDriveEpochBakePlacesIconOnRecordedPhase"/>): convert the segment
        /// [startUT,endUT] to hyperbolic eccentric anomaly via EccentricAnomalyAtUT, sample with
        /// getPositionFromEccAnomalyWithSemiMinorAxis, and check the draw range is a bounded OPEN arc.
        /// Uses the real escape orbit from the evidence log (sma=-3818300 ecc=1.1916, segment
        /// 63966985.6..64044032.7).
        /// </summary>
        [InGameTest(Category = "GhostMap", Scene = GameScenes.FLIGHT,
            Description = "Hyperbolic escape ghost orbit LINE is clipped to its segment window (open sub-arc), not drawn as the full stock hyperbola")]
        public void HyperbolicArcClipBoundsLineToSegmentWindow()
        {
            CelestialBody kerbin = FlightGlobals.Bodies?.Find(b => b.bodyName == "Kerbin");
            if (kerbin == null)
            {
                InGameAssert.Skip("Kerbin not found in FlightGlobals.Bodies");
                return;
            }

            const double rawEpoch = 63966985.6;
            const double segStart = 63966985.6;
            const double segEnd = 64044032.7;
            var orbit = new Orbit();
            orbit.SetOrbit(1.3329, 1.1916, -3818300.0, 50.0, 60.0, 0.0238, rawEpoch, kerbin);
            orbit.Init();
            InGameAssert.IsTrue(orbit.eccentricity > 1.0,
                $"test orbit must be hyperbolic (ecc={orbit.eccentricity:F3})");
            InGameAssert.IsTrue(double.IsInfinity(orbit.period) || double.IsNaN(orbit.period),
                $"a hyperbolic orbit must NOT have a finite period (period={orbit.period}), the " +
                $"full-period early-return must never fire for it");

            // NOTE: this MIRRORS GhostOrbitArcPatch.Prefix's hyperbolic path rather than invoking the
            // Harmony patch (which needs live OrbitRendererBase + ghostOrbitBounds wiring), like the
            // director-drive in-game test. So the endpoint-position checks are a self-consistency pin
            // on the stock Orbit API the patch relies on; the load-bearing guard is windowSpan <
            // stockSpan below (the clip is a strict sub-arc, not the full open hyperbola).
            // --- The clip's anomaly bounds (GhostOrbitArcPatch.Prefix, hyperbolic path) ---
            double fromH = orbit.EccentricAnomalyAtUT(segStart);
            double toH = orbit.EccentricAnomalyAtUT(segEnd);
            InGameAssert.IsFalse(double.IsNaN(fromH) || double.IsNaN(toH),
                $"hyperbolic eccentric anomaly bounds must be finite (fromH={fromH}, toH={toH})");
            // Hyperbola is monotonic in H, no periapsis wraparound. The window must be a forward,
            // non-degenerate sweep (toH strictly past fromH).
            InGameAssert.IsGreaterThan(toH - fromH, 1e-6,
                $"hyperbolic anomaly window must be a forward sweep (fromH={fromH:F4}, toH={toH:F4})");

            // The FULL stock hyperbolic sweep (OrbitRendererBase.UpdateSpline else-branch):
            // st = -acos(-1/ecc) .. end = +acos(-1/ecc). The clipped window must be a STRICT
            // subset of that, i.e. the line stops short of the asymptotes, not the whole hyperbola.
            // The asymptote acos(-1/ecc) is a TRUE-anomaly bound, but EccentricAnomalyAtUT returns the
            // hyperbolic ECCENTRIC anomaly H (range +/-infinity via sinh), not the true anomaly. Compare
            // like with like: convert the window bounds to true anomaly via Orbit.GetTrueAnomaly(H)
            // (KSP's hyperbolic branch: 2*atan2(sqrt(e+1)*sinh(H/2), sqrt(e-1)*cosh(H/2)), which tends to
            // +/-acos(-1/ecc) as H -> +/-infinity), then check containment + span in true anomaly.
            double stockHalfSweep = System.Math.Acos(-1.0 / orbit.eccentricity);
            double fromV = orbit.GetTrueAnomaly(fromH);
            double toV = orbit.GetTrueAnomaly(toH);
            InGameAssert.IsGreaterThan(fromV, -stockHalfSweep,
                $"clipped start true anomaly ({fromV:F4}) must be inside the stock sweep start " +
                $"(-{stockHalfSweep:F4})");
            InGameAssert.IsLessThan(toV, stockHalfSweep,
                $"clipped end true anomaly ({toV:F4}) must be inside the stock sweep end ({stockHalfSweep:F4})");
            double windowSpan = toV - fromV;
            double stockSpan = 2.0 * stockHalfSweep;
            InGameAssert.IsLessThan(windowSpan, stockSpan,
                $"clipped window true-anomaly span ({windowSpan:F4}) must be a strict sub-arc of the full " +
                $"stock hyperbola span ({stockSpan:F4}); else the line is the whole open hyperbola");

            // --- Sample the clipped arc exactly as the patch does and verify the endpoints land on
            // the recorded segment positions (the line is bounded to the window), the arc is open
            // (endpoints are far apart, not a closed loop), and every sample is finite + in-SOI. ---
            double semiMinorAxis = orbit.semiMinorAxis;
            const int count = 180; // stock OrbitPoints.Length at sampleResolution=2.0
            double interval = (toH - fromH) / (count - 1);
            double soi = kerbin.sphereOfInfluence;
            Vector3d firstSample = Vector3d.zero, lastSample = Vector3d.zero;
            double maxR = 0.0;
            for (int i = 0; i < count; i++)
            {
                Vector3d p = orbit.getPositionFromEccAnomalyWithSemiMinorAxis(
                    fromH + interval * i, semiMinorAxis);
                InGameAssert.IsFalse(double.IsNaN(p.x) || double.IsInfinity(p.x),
                    $"clipped hyperbolic sample {i} must be finite");
                double r = (p - kerbin.position).magnitude;
                maxR = System.Math.Max(maxR, r);
                if (i == 0) firstSample = p;
                if (i == count - 1) lastSample = p;
            }

            // The clipped arc endpoints must match the recorded-segment world positions (this is the
            // "bounded to the window" property: the line begins/ends where the recorded escape does).
            // getPositionAtUT returns the same world frame as getPositionFromEccAnomalyWithSemiMinorAxis
            // (referenceBody.position + relative.xzy), so the two are directly comparable.
            Vector3d windowStartPos = orbit.getPositionAtUT(segStart);
            Vector3d windowEndPos = orbit.getPositionAtUT(segEnd);
            double startErr = (firstSample - windowStartPos).magnitude;
            double endErr = (lastSample - windowEndPos).magnitude;
            // Tolerance: 1 km against an arc that spans tens of thousands of km.
            InGameAssert.IsLessThan(startErr, 1000.0,
                $"clipped arc start must land on the recorded window start (err={startErr:F1} m)");
            InGameAssert.IsLessThan(endErr, 1000.0,
                $"clipped arc end must land on the recorded window end (err={endErr:F1} m)");

            // Open arc: the two endpoints are far apart (a clipped open hyperbola), NOT a near-closed
            // loop. They span the full escape, so the chord is a large fraction of the SOI.
            double chord = (lastSample - firstSample).magnitude;
            InGameAssert.IsGreaterThan(chord, soi * 0.5,
                $"clipped escape arc must be open (endpoint chord={chord:F0} m vs SOI={soi:F0} m)");

            ParsekLog.Info("TestRunner",
                $"HyperbolicArcClipBoundsLineToSegmentWindow: ecc={orbit.eccentricity:F4} " +
                $"fromH={fromH:F4} toH={toH:F4} fromV={fromV:F4} toV={toV:F4} stockHalfSweep={stockHalfSweep:F4} " +
                $"windowSpan={windowSpan:F4} stockSpan={stockSpan:F4} " +
                $"startErr={startErr:F1}m endErr={endErr:F1}m chord={chord:F0}m maxR={maxR:F0}m SOI={soi:F0}m");
        }

