                Vessel vessel = FlightGlobals.ActiveVessel;
                if (vessel != null
                    && vessel.isEVA
                    && IsExpectedEvaVessel(vessel, expectedCrewName)
                    && (vessel.LandedOrSplashed
                        || vessel.situation == Vessel.Situations.LANDED
                        || vessel.situation == Vessel.Situations.SPLASHED))
                {
                    yield break;
                }

                yield return null;
            }

            Vessel timedOutVessel = FlightGlobals.ActiveVessel;
            InGameAssert.Fail(
                $"WaitForActiveEvaSurfaceSettled timed out after {timeoutSeconds:F0}s " +
                $"(activeVessel='{timedOutVessel?.vesselName ?? "null"}', " +
                $"isEva={timedOutVessel?.isEVA == true}, " +
                $"situation={timedOutVessel?.situation.ToString() ?? "null"}, " +
                $"landedOrSplashed={timedOutVessel?.LandedOrSplashed == true})");
        }

        private static bool TryFindEvaRecording(
            RecordingTree tree,
            string expectedCrewName,
            out Recording evaRecording)
        {
            evaRecording = null;
            if (tree?.Recordings == null)
                return false;

            foreach (Recording candidate in tree.Recordings.Values)
            {
                if (candidate == null || string.IsNullOrEmpty(candidate.EvaCrewName))
                    continue;
                if (!string.IsNullOrEmpty(expectedCrewName)
                    && !string.Equals(candidate.EvaCrewName, expectedCrewName, System.StringComparison.Ordinal)
                    && !candidate.EvaCrewName.Contains(expectedCrewName)
                    && (string.IsNullOrEmpty(candidate.VesselName)
                        || !candidate.VesselName.Contains(expectedCrewName)))
                {
                    continue;
                }

                evaRecording = candidate;
                return true;
            }

            return false;
        }

        private static bool IsExpectedEvaVessel(Vessel vessel, string expectedCrewName)
        {
            if (vessel == null || !vessel.isEVA)
                return false;
            if (string.IsNullOrEmpty(expectedCrewName))
                return true;
            return string.Equals(vessel.vesselName, expectedCrewName, System.StringComparison.Ordinal)
                || vessel.vesselName.Contains(expectedCrewName);
        }

        private static int CountPartNodes(ConfigNode snapshot)
        {
            return snapshot?.GetNodes("PART")?.Length ?? 0;
        }

        private sealed class ForcedBallisticLiveVesselViewForRuntimeTest : IRecordingFinalizationVesselView
        {
            private readonly Vessel vessel;

            internal ForcedBallisticLiveVesselViewForRuntimeTest(Vessel vessel)
            {
                this.vessel = vessel;
            }

            public uint PersistentId => vessel.persistentId;
            public Vessel.Situations Situation => Vessel.Situations.FLYING;
            public string BodyName => vessel.mainBody?.name
                ?? vessel.orbit?.referenceBody?.name
                ?? "(unknown-body)";
            public bool IsInAtmosphere
            {
                get
                {
                    CelestialBody body = vessel.mainBody ?? vessel.orbit?.referenceBody;
                    return body != null
                        && body.atmosphere
                        && vessel.altitude < body.atmosphereDepth;
                }
            }
            public bool IsPacked => vessel.packed;
            public bool IsLoaded => vessel.loaded;
            public double Latitude => vessel.latitude;
            public double Longitude => vessel.longitude;
            public double Altitude => vessel.altitude;
            public double HeightFromTerrain => vessel.heightFromTerrain;
            public Quaternion SurfaceRelativeRotation => vessel.srfRelRotation;
            public Vessel RawVessel => vessel;

            public bool TryGetOrbit(out RecordingFinalizationOrbitView orbit)
            {
                orbit = default(RecordingFinalizationOrbitView);
                CelestialBody body = vessel.mainBody ?? vessel.orbit?.referenceBody;
                if (body == null)
                    return false;

                Orbit source = vessel.orbit;
                orbit = new RecordingFinalizationOrbitView
                {
                    ReferenceBodyName = body.name,
                    ReferenceBodyHasAtmosphere = body.atmosphere,
                    ReferenceBodyAtmosphereDepth = body.atmosphereDepth,
                    Inclination = source?.inclination ?? 0.0,
                    Eccentricity = 1.0,
                    SemiMajorAxis = source?.semiMajorAxis ?? body.Radius + System.Math.Max(0.0, vessel.altitude),
                    LongitudeOfAscendingNode = source?.LAN ?? 0.0,
                    ArgumentOfPeriapsis = source?.argumentOfPeriapsis ?? 0.0,
                    MeanAnomalyAtEpoch = source?.meanAnomalyAtEpoch ?? 0.0,
                    Epoch = source?.epoch ?? Planetarium.GetUniversalTime(),
                    PeriapsisAltitude = -1.0
                };
                return true;
            }
        }

        private static void DiscardActiveTreeForRuntimeTest(ParsekFlight flight, string reason)
        {
            if (flight == null)
                return;

            if (!flight.HasActiveTree)
            {
                if (flight.IsRecording)
                    flight.StopRecording();
                return;
            }

            try
            {
                ParsekFlightDiscardActiveTreeForSuppressedSceneExitMethod.Invoke(
                    flight,
                    new object[]
                    {
                        HighLogic.LoadedScene,
                        Planetarium.GetUniversalTime(),
                        reason ?? "runtime test cleanup",
                        false
                    });
            }
            catch (TargetInvocationException ex)
            {
                InGameAssert.Fail(
                    $"DiscardActiveTreeForSuppressedSceneExit cleanup threw " +
                    $"{ex.InnerException?.GetType().Name ?? ex.GetType().Name}: " +
                    $"{ex.InnerException?.Message ?? ex.Message}");
            }
        }

        private static IEnumerator WaitForEvaBranchCount(
            RecordingTree tree,
            int expectedCount,
            float timeoutSeconds,
            string context)
        {
            float deadline = Time.time + timeoutSeconds;
            while (Time.time < deadline)
            {
                if (CountEvaBranches(tree) >= expectedCount)
                    yield break;

                yield return null;
            }

            InGameAssert.Fail(
                $"WaitForEvaBranchCount timed out after {timeoutSeconds:F0}s ({context}); " +
                $"expected>={expectedCount} actual={CountEvaBranches(tree)}");
        }

        // Waits until the active vessel is the given pid, or Skips on timeout. The sole caller is the
        // EVA-twice switch-BACK to the source capsule, driven through stock FlightGlobals.SetActiveVessel
        // right after the first EVA kerbal was teleported clear of the hatch. KSP sometimes logs
        // "Switching To Vessel <capsule>" but never completes the transition (the just-teleported
        // from-vessel is mid-settle, or the spawnEVA auto-focus re-steals focus). That is stock-KSP
        // not honoring a programmatic switch, NOT a Parsek regression, and the background-parent path
        // under test can only be set up once the capsule is active again — so a non-switch is a clean
        // Skip, consistent with this test's other "KSP did not cooperate" guards.
        private static IEnumerator WaitForActiveVesselPid(uint expectedPid, float timeoutSeconds)
        {
            float deadline = Time.time + timeoutSeconds;
            while (Time.time < deadline)
            {
                if (FlightGlobals.ActiveVessel != null
                    && FlightGlobals.ActiveVessel.persistentId == expectedPid)
                {
                    yield break;
                }

                yield return null;
            }

            InGameAssert.Skip(
                $"KSP did not complete the programmatic switch to the expected vessel within {timeoutSeconds:F0}s " +
                $"(expected pid={expectedPid} active pid={FlightGlobals.ActiveVessel?.persistentId ?? 0u}); " +
                "cannot establish the active source capsule, so the background-parent second-EVA path is untestable");
        }

        // Waits (without asserting) until the active vessel is no longer the given pid, or the
        // timeout elapses. Used to observe KSP's stock auto-switch to a freshly spawned EVA kerbal;
        // the caller decides whether a non-switch is a Skip or an error.
        private static IEnumerator WaitForActiveVesselToLeavePid(uint pid, float timeoutSeconds)
        {
            float deadline = Time.time + timeoutSeconds;
            while (Time.time < deadline)
            {
                Vessel active = FlightGlobals.ActiveVessel;
                if (active == null || active.persistentId != pid)
                    yield break;

                yield return null;
            }
        }

        // Moves a loaded vessel a fixed distance horizontally away from an anchor vessel, so it stops
        // obstructing the anchor's hatch. Used to step the first EVA kerbal off the capsule ladder
        // before the second EVA (KSP's spawnEVA refuses a second EVA while the only hatch is blocked).
        private static void MoveVesselClearOfAnchor(Vessel mover, Vessel anchor, double metres)
        {
            if (mover == null || anchor == null || VesselSetPositionMethod == null)
                return;

            Vector3d anchorPos = anchor.GetWorldPos3D();
            Vector3d moverPos = mover.GetWorldPos3D();
            // Derive up from body+position rather than anchor.upAxis: the anchor is backgrounded after
            // the focus switch, so its cached upAxis can be stale.
            Vector3d up = FlightGlobals.getUpAxis(anchor.mainBody, anchorPos);
            Vector3d awayFromAnchor = moverPos - anchorPos;
            // Horizontal component of the anchor->mover direction (project out the local up axis).
            Vector3d horizontal = awayFromAnchor - up * Vector3d.Dot(awayFromAnchor, up);
            if (horizontal.magnitude < 0.1)
                horizontal = (Vector3d)anchor.transform.forward; // degenerate: mover directly above anchor
            horizontal = horizontal.normalized;

            // Teleport only — velocity is intentionally left untouched; the kerbal is relocated and left
            // to settle over the subsequent wait frames. Do not also zero velocity / nudge the rigidbody.
            VesselSetPositionMethod.Invoke(mover, new object[] { moverPos + horizontal * metres });
        }

        // Reflects FlightEVA.HatchIsObstructedMore(Part, Transform) — the stricter check (outward ray +
        // inward ray + overlap sphere) that spawnEVA applies to the PRIMARY hatch, so this precheck
        // matches the gate that would actually refuse the second EVA. Returns false (treat as clear)
        // when the check is unavailable so the test still proceeds (spawnEVA enforces the real gate);
        // logs a breadcrumb so a later "timed out instead of skipping" investigation has a trail.
        private static bool IsHatchObstructed(Part part, Transform airlock)
        {
            if (part == null || airlock == null)
                return false;
            if (FlightEvaHatchIsObstructedMoreMethod == null)
            {
                ParsekLog.Verbose("TestRunner",
                    "IsHatchObstructed: FlightEVA.HatchIsObstructedMore not reflectable; treating hatch as clear");
                return false;
            }

            try
            {
                return (bool)FlightEvaHatchIsObstructedMoreMethod.Invoke(null, new object[] { part, airlock });
            }
            catch
            {
                ParsekLog.Verbose("TestRunner",
                    "IsHatchObstructed: HatchIsObstructedMore invoke threw; treating hatch as clear");
                return false;
            }
        }

        private static int CountEvaBranches(RecordingTree tree)
        {
            if (tree?.BranchPoints == null)
                return 0;

            return tree.BranchPoints.Count(bp => bp != null && bp.Type == BranchPointType.EVA);
        }

        private static int CountCrewInParts(Vessel vessel)
        {
            if (vessel?.parts == null)
                return 0;

            int count = 0;
            foreach (Part part in vessel.parts)
                count += part?.protoModuleCrew?.Count ?? 0;
            return count;
        }

