        #region Coalescer

        [InGameTest(Category = "Coalescer", Scene = GameScenes.FLIGHT, RunLast = true,
            AllowBatchExecution = false,
            RestoreBatchFlightBaselineAfterExecution = true,
            BatchSkipReason = "Isolated-run only — excluded from ordinary Run All / Run category because this test starts a recording and stages the active vessel. Use Run All + Isolated or the row play button on a disposable two-controller decoupler craft.",
            Description = "Controlled-child staging logs the live seed residual decision")]
        public IEnumerator ControlledChildBreakupSeed_LogsLiveResidualDecision()
        {
            var flight = ParsekFlight.Instance;
            InGameAssert.IsNotNull(flight, "ParsekFlight.Instance required");

            var vessel = FlightGlobals.ActiveVessel;
            if (vessel == null)
            {
                InGameAssert.Skip("no active vessel");
                yield break;
            }
            if (flight.IsRecording)
            {
                InGameAssert.Skip("requires an idle active vessel (recording already active)");
                yield break;
            }
            if (RecordingStore.HasPendingTree)
            {
                InGameAssert.Skip("requires no pending tree before staging");
                yield break;
            }
            if (!HasAtLeastTwoCommandModules(vessel, out int commandModuleCount))
            {
                InGameAssert.Skip(
                    $"requires an active vessel with 2+ command modules/probe cores, got {commandModuleCount}");
                yield break;
            }
            if (!HasDecouplerModule(vessel, out int decouplerCount))
            {
                InGameAssert.Skip("requires an active vessel with a decoupler or separator module");
                yield break;
            }
            if (FlightInputHandler.state == null)
            {
                InGameAssert.Skip("FlightInputHandler.state is null");
                yield break;
            }

            float originalThrottle = FlightInputHandler.state.mainThrottle;
            var captured = new List<string>();
            var priorObserver = ParsekLog.TestObserverForTesting;
            var priorVerbose = ParsekLog.VerboseOverrideForTesting;
            bool originalGhostRenderTracing = ParsekSettings.Current?.ghostRenderTracing ?? false;
            bool startedByTest = false;

            try
            {
                ParsekLog.VerboseOverrideForTesting = true;
                ParsekLog.TestObserverForTesting = line => { captured.Add(line); priorObserver?.Invoke(line); };
                // The staged split opens the Trace-Sep window via OnPartJointBreak.
                if (ParsekSettings.Current != null)
                    ParsekSettings.Current.ghostRenderTracing = true;

                flight.StartRecording();
                startedByTest = flight.IsRecording;
                InGameAssert.IsTrue(startedByTest,
                    "ParsekFlight.StartRecording should start before controlled-child staging");

                yield return new WaitForSeconds(0.25f);
                yield return InGameTestRunner.WaitForStockStageManagerReady(10f);

                FlightInputHandler.state.mainThrottle = Mathf.Max(FlightInputHandler.state.mainThrottle, 1f);
                KSP.UI.Screens.StageManager.ActivateNextStage();

                string decisionLine = null;
                float deadline = Time.time + 10f;
                while (Time.time < deadline)
                {
                    decisionLine = FindControlledChildSeedResidualDecisionLog(captured);
                    if (decisionLine != null)
                        break;

                    yield return new WaitForFixedUpdate();
                }

                if (decisionLine == null)
                {
                    string otherSeedLine = captured.LastOrDefault(IsControlledChildSeedLog);
                    if (otherSeedLine != null)
                    {
                        InGameAssert.Fail(
                            "Controlled child seed log did not include a measured residual decision: " +
                            otherSeedLine);
                    }

                    InGameAssert.Skip(
                        "requires the next stage to separate a controllable child; no controlled-child seed decision log was observed");
                    yield break;
                }

                InGameAssert.Contains(decisionLine, "seedLiveRootDist=",
                    "Seed decision log should include raw live-root distance for postmortems");
                InGameAssert.Contains(decisionLine, "propagatedResidual=",
                    "Seed decision log should include propagated residual");
                InGameAssert.IsFalse(decisionLine.Contains("propagatedResidual=n/a"),
                    "Seed decision log should include a numeric propagated residual");

                string bgSampleLine = null;
                double bgSampleDeltaMeters = double.NaN;
                deadline = Time.time + 5f;
                while (Time.time < deadline)
                {
                    if (TryFindLoadedBackgroundAbsoluteSampleLog(captured, out bgSampleLine, out bgSampleDeltaMeters))
                        break;

                    yield return new WaitForFixedUpdate();
                }

                if (bgSampleLine == null)
                {
                    InGameAssert.Skip(
                        "controlled child seed observed but no ordinary loaded/unpacked BG_CreateAbs trace sample was observed");
                    yield break;
                }

                InGameAssert.Contains(bgSampleLine, "llaSource=transform",
                    "Loaded/unpacked ordinary background samples should derive LLA from transform.position");
                InGameAssert.IsLessThan(bgSampleDeltaMeters, BackgroundLoadedSampleRoundTripToleranceMeters,
                    $"Loaded background sample should round-trip near the live transform; delta={bgSampleDeltaMeters:F3} line='{bgSampleLine}'");

                ParsekLog.Info("TestRunner",
                    $"Controlled child seed residual decision observed: commandModules={commandModuleCount} " +
                    $"decouplers={decouplerCount} bgSampleDelta={bgSampleDeltaMeters:F3}m " +
                    $"line='{decisionLine}' bgLine='{bgSampleLine}'");
            }
            finally
            {
                if (FlightInputHandler.state != null)
                    FlightInputHandler.state.mainThrottle = originalThrottle;
                if (ParsekSettings.Current != null)
                    ParsekSettings.Current.ghostRenderTracing = originalGhostRenderTracing;
                ParsekLog.TestObserverForTesting = priorObserver;
                ParsekLog.VerboseOverrideForTesting = priorVerbose;

                var cleanupFlight = ParsekFlight.Instance;
                if (startedByTest && cleanupFlight != null && cleanupFlight.IsRecording)
                    cleanupFlight.StopRecording();
            }
        }

        [InGameTest(Category = "Coalescer", Scene = GameScenes.FLIGHT, RunLast = true,
            AllowBatchExecution = false,
            RestoreBatchFlightBaselineAfterExecution = true,
            BatchSkipReason = "Isolated-run only - this test starts a recording and stages the active vessel to assert the parent-anchor contract stamping on a controlled-decoupled child. Use Run All + Isolated or the row play button on a disposable two-controller decoupler craft.",
            Description = "Controlled-decoupled child stamps ParentAnchorRecordingId pointing at the focused parent recording at split time")]
        public IEnumerator ControlledChildBreakup_StampsParentAnchorContract()
        {
            var flight = ParsekFlight.Instance;
            InGameAssert.IsNotNull(flight, "ParsekFlight.Instance required");

            var vessel = FlightGlobals.ActiveVessel;
            if (vessel == null)
            {
                InGameAssert.Skip("no active vessel");
                yield break;
            }
            if (flight.IsRecording)
            {
                InGameAssert.Skip("requires an idle active vessel (recording already active)");
                yield break;
            }
            if (RecordingStore.HasPendingTree)
            {
                InGameAssert.Skip("requires no pending tree before staging");
                yield break;
            }
            if (!HasAtLeastTwoCommandModules(vessel, out int commandModuleCount))
            {
                InGameAssert.Skip(
                    $"requires an active vessel with 2+ command modules/probe cores, got {commandModuleCount}");
                yield break;
            }
            if (!HasDecouplerModule(vessel, out int decouplerCount))
            {
                InGameAssert.Skip("requires an active vessel with a decoupler or separator module");
                yield break;
            }
            if (FlightInputHandler.state == null)
            {
                InGameAssert.Skip("FlightInputHandler.state is null");
                yield break;
            }

            float originalThrottle = FlightInputHandler.state.mainThrottle;
            bool startedByTest = false;

            try
            {
                flight.StartRecording();
                startedByTest = flight.IsRecording;
                InGameAssert.IsTrue(startedByTest,
                    "ParsekFlight.StartRecording should start before controlled-child staging");

                yield return new WaitForSeconds(0.25f);
                yield return InGameTestRunner.WaitForStockStageManagerReady(10f);

                // Capture the focused parent recording id BEFORE staging.
                var activeTreePre = RecordingStore.PendingTree;
                InGameAssert.IsNotNull(activeTreePre, "PendingTree must exist before staging");
                string parentRecId = activeTreePre?.ActiveRecordingId;
                InGameAssert.IsFalse(string.IsNullOrEmpty(parentRecId),
                    "parent recording id required before staging");

                FlightInputHandler.state.mainThrottle = Mathf.Max(FlightInputHandler.state.mainThrottle, 1f);
                KSP.UI.Screens.StageManager.ActivateNextStage();

                // The Coalescer's BREAKUP window is 0.5s; wait long enough for
                // the controlled-child Recording to land in the active tree.
                Recording childRec = null;
                float deadline = Time.time + 5f;
                while (Time.time < deadline)
                {
                    yield return new WaitForFixedUpdate();
                    childRec = FindFirstControlledChildRecording(parentRecId);
                    if (childRec != null)
                        break;
                }

                if (childRec == null)
                {
                    InGameAssert.Skip(
                        "no controlled-decoupled child recording was produced by the next stage; "
                        + "skipping (test requires a stage that produces a controlled child, not pure debris)");
                    yield break;
                }

                InGameAssert.IsFalse(childRec.IsDebris,
                    $"controlled-decoupled child must have IsDebris=false, got IsDebris={childRec.IsDebris} for recId={childRec.RecordingId}");
                InGameAssert.AreEqual(parentRecId, childRec.ParentAnchorRecordingId,
                    $"controlled child should carry ParentAnchorRecordingId={parentRecId}; got '{childRec.ParentAnchorRecordingId}' (this is the parent-anchor contract that Phase 2 of the controlled-child-parent-anchored fix lands)");
            }
            finally
            {
                if (FlightInputHandler.state != null)
                    FlightInputHandler.state.mainThrottle = originalThrottle;

                var cleanupFlight = ParsekFlight.Instance;
                if (startedByTest && cleanupFlight != null && cleanupFlight.IsRecording)
                    cleanupFlight.StopRecording();
            }
        }

        private static Recording FindFirstControlledChildRecording(string parentRecId)
        {
            if (string.IsNullOrEmpty(parentRecId))
                return null;

            var activeTree = RecordingStore.PendingTree;
            if (activeTree?.Recordings == null)
                return null;

            foreach (var pair in activeTree.Recordings)
            {
                Recording rec = pair.Value;
                if (rec == null)
                    continue;
                if (rec.IsDebris)
                    continue;
                if (string.IsNullOrEmpty(rec.ParentAnchorRecordingId))
                    continue;
                if (!string.Equals(rec.ParentAnchorRecordingId, parentRecId, System.StringComparison.Ordinal))
                    continue;
                return rec;
            }

            return null;
        }

        private static bool HasAtLeastTwoCommandModules(Vessel vessel, out int commandModuleCount)
        {
            commandModuleCount = 0;
            if (vessel?.parts == null)
                return false;

            foreach (Part part in vessel.parts)
            {
                if (part == null)
                    continue;
                if (part.FindModuleImplementing<ModuleCommand>() != null)
                    commandModuleCount++;
            }

            return commandModuleCount >= 2;
        }

        private static bool HasDecouplerModule(Vessel vessel, out int decouplerCount)
        {
            decouplerCount = 0;
            if (vessel?.parts == null)
                return false;

            foreach (Part part in vessel.parts)
            {
                if (part?.Modules == null)
                    continue;

                for (int i = 0; i < part.Modules.Count; i++)
                {
                    string moduleName = part.Modules[i]?.moduleName;
                    if (moduleName == "ModuleDecouple" || moduleName == "ModuleAnchoredDecoupler")
                        decouplerCount++;
                }
            }

            return decouplerCount > 0;
        }

        private static string FindControlledChildSeedResidualDecisionLog(List<string> lines)
        {
            if (lines == null)
                return null;

            for (int i = lines.Count - 1; i >= 0; i--)
            {
                string line = lines[i];
                if (!IsControlledChildSeedLog(line))
                    continue;

                if (line.Contains("Controlled child initial seed replaced with live sample"))
                    return line;
                if (line.Contains("source=decouple-callback")
                    && line.Contains("seedLiveRootDist=")
                    && line.Contains("propagatedResidual="))
                    return line;
            }

            return null;
        }

        private static bool IsControlledChildSeedLog(string line)
        {
            return line != null
                && line.Contains("[Coalescer]")
                && line.Contains("Controlled child initial seed");
        }

        private static bool TryFindLoadedBackgroundAbsoluteSampleLog(
            List<string> lines,
            out string line,
            out double deltaMeters)
        {
            line = null;
            deltaMeters = double.NaN;
            if (lines == null)
                return false;

            for (int i = lines.Count - 1; i >= 0; i--)
            {
                string candidate = lines[i];
                if (candidate == null
                    || !candidate.Contains("[BG_CreateAbs]")
                    || !candidate.Contains(" packed=False")
                    || !candidate.Contains(" preferRoot=False"))
                {
                    continue;
                }

                if (!TryExtractTraceDeltaMeters(candidate, out double parsedDelta))
                    continue;

                line = candidate;
                deltaMeters = parsedDelta;
                return true;
            }

            return false;
        }

        private static bool TryExtractTraceDeltaMeters(string line, out double deltaMeters)
        {
            deltaMeters = double.NaN;
            if (string.IsNullOrEmpty(line))
                return false;

            const string marker = " |delta|=";
            int start = line.IndexOf(marker);
            if (start < 0)
                return false;

            start += marker.Length;
            int end = start;
            while (end < line.Length)
            {
                char c = line[end];
                if (!(char.IsDigit(c) || c == '-' || c == '+' || c == '.' || c == 'E' || c == 'e'))
                    break;
                end++;
            }

            if (end <= start)
                return false;

            return double.TryParse(
                line.Substring(start, end - start),
                NumberStyles.Float,
                CultureInfo.InvariantCulture,
                out deltaMeters);
        }

