        [InGameTest(Category = "GhostAudio", Scene = GameScenes.FLIGHT,
            Description = "#265: PauseAllAudio pauses playing AudioSource, UnpauseAllAudio resumes")]
        public IEnumerator PauseUnpauseAudio_RealAudioSource()
        {
            var go = new GameObject("ParsekTest_AudioGhost");
            runner.TrackForCleanup(go);
            var audioSource = go.AddComponent<AudioSource>();
            audioSource.clip = AudioClip.Create("test_silence", 44100, 1, 44100, false);
            audioSource.loop = true;
            audioSource.volume = 0f;
            audioSource.Play();

            yield return null; // let audio system process

            InGameAssert.IsTrue(audioSource.isPlaying,
                "AudioSource should be playing before pause");

            var info = new AudioGhostInfo
            {
                partPersistentId = 99999,
                moduleIndex = 0,
                audioSource = audioSource,
                currentPower = 0.75f
            };
            var state = new GhostPlaybackState
            {
                audioInfos = new Dictionary<ulong, AudioGhostInfo> { { 99999UL, info } }
            };

            GhostPlaybackLogic.PauseAllAudio(state);
            yield return null;

            InGameAssert.IsFalse(audioSource.isPlaying,
                "AudioSource should be paused after PauseAllAudio");
            InGameAssert.ApproxEqual(0.75f, info.currentPower, 0.001f,
                "currentPower should survive pause");

            GhostPlaybackLogic.UnpauseAllAudio(state);
            yield return null;

            InGameAssert.IsTrue(audioSource.isPlaying,
                "AudioSource should be playing after UnpauseAllAudio");
            InGameAssert.ApproxEqual(0.75f, info.currentPower, 0.001f,
                "currentPower should survive unpause");

            ParsekLog.Verbose("TestRunner",
                "GhostAudio pause/unpause cycle verified with real AudioSource + currentPower preservation");
        }

        [InGameTest(Category = "GhostAudio", Scene = GameScenes.FLIGHT,
            Description = "Phantom-engine-after-decouple regression: StopFxAndAudioForSubtree must stop a child engine's looping AudioSource on the parent ghost when the decoupler fires, not just the decoupler's own pid.")]
        public IEnumerator StopFxAndAudioForSubtree_DecoupledChildEngineAudioStops()
        {
            const uint decouplerPid = 100;
            const uint enginePid = 200;
            ulong engineKey = FlightRecorder.EncodeEngineKey(enginePid, 0);

            var engineGo = new GameObject("ParsekTest_DecoupledEngineAudio");
            runner.TrackForCleanup(engineGo);
            var engineSource = engineGo.AddComponent<AudioSource>();
            engineSource.clip = AudioClip.Create("test_decoupled_engine", 44100, 1, 44100, false);
            engineSource.loop = true;
            engineSource.volume = 0f;
            engineSource.Play();

            yield return null;
            InGameAssert.IsTrue(engineSource.isPlaying,
                "Engine AudioSource should be playing before the decouple");

            var state = new GhostPlaybackState
            {
                audioInfos = new Dictionary<ulong, AudioGhostInfo>
                {
                    {
                        engineKey,
                        new AudioGhostInfo
                        {
                            partPersistentId = enginePid,
                            moduleIndex = 0,
                            audioSource = engineSource,
                            currentPower = 1f
                        }
                    }
                },
                partTree = new Dictionary<uint, List<uint>>
                {
                    { decouplerPid, new List<uint> { enginePid } }
                }
            };

            GhostPlaybackLogic.StopFxAndAudioForSubtree(state, decouplerPid, state.partTree);
            yield return null;

            // Pre-fix: only decouplerPid's audio info would be processed, so the
            // engine child's AudioSource would keep playing. Post-fix: subtree
            // walk reaches the engine and StopAudioForPart stops it.
            InGameAssert.IsFalse(engineSource.isPlaying,
                "Engine AudioSource on a child of the decoupled subtree must be stopped, not just the decoupler's own pid");
            InGameAssert.ApproxEqual(0f, state.audioInfos[engineKey].currentPower, 0.001f,
                "Engine currentPower must be cleared by the subtree walk");

            ParsekLog.Verbose("TestRunner",
                "Phantom-engine-after-decouple regression: subtree walk stopped the child engine's AudioSource on decouple");
        }

        [InGameTest(Category = "GhostAudio", Scene = GameScenes.SPACECENTER,
            Description = "KSC terminal explosion fallback queues a fire-and-forget AudioSource; run from Ctrl+Shift+T in the Space Center scene")]
        public IEnumerator KscExplosionFallbackAudio_FireAndForgetSourceSurvivesGhostDestroy()
        {
            GhostPlaybackLogic.ResetForTesting();
            var ghostRoot = new GameObject("ParsekTest_KscExplosionAudioGhost");
            runner.TrackForCleanup(ghostRoot);
            ghostRoot.transform.position = Vector3.zero;
            AudioClip clip = AudioClip.Create("parsek_test_ksc_explosion_silence", 88200, 1, 44100, false);

            try
            {
                var existingSources = new HashSet<int>(
                    UnityEngine.Object.FindObjectsOfType<AudioSource>()
                        .Select(source => source.GetInstanceID()));

                bool queued = GhostPlaybackLogic.TryPlayIndependentExplosionOneShot(
                    ghostRoot.transform.position,
                    atmosphereFactor: 1f,
                    distanceMeters: 0.0,
                    power: 0.5,
                    contextDescription: "KSC in-game fallback audio test",
                    resolveExplosionAudioCandidate: () => new GhostPlaybackLogic.ExplosionOneShotAudioCandidate
                    {
                        canPlay = true,
                        clipPath = "parsek_test_ksc_explosion_silence",
                        clip = clip,
                        clipLengthSeconds = clip.length,
                        volume = 0.01f,
                        priority = GhostAudioPresets.BaselineGameAudioPriority
                    });

                InGameAssert.IsTrue(queued,
                    "KSC fallback explosion audio should queue an independent AudioSource");
                yield return null;

                var createdSource = UnityEngine.Object.FindObjectsOfType<AudioSource>()
                    .FirstOrDefault(source =>
                        source != null
                        && source.gameObject.name == GhostPlaybackLogic.ExplosionOneShotAudioObjectName
                        && !existingSources.Contains(source.GetInstanceID()));
                InGameAssert.IsNotNull(createdSource,
                    "Fallback explosion audio must create an independent fire-and-forget AudioSource");
                runner.TrackForCleanup(createdSource.gameObject);
                InGameAssert.IsTrue(createdSource.transform.parent == null,
                    "Fallback explosion audio must not be parented to the ghost that KSC may destroy immediately");
                InGameAssert.ApproxEqual(GhostVisualBuilder.GhostAudioSpatialBlend, createdSource.spatialBlend, 0.0001f,
                    "Fallback explosion audio should use the same spatial blend as ghost one-shot audio");
                InGameAssert.AreEqual(GhostAudioPresets.BaselineGameAudioPriority, createdSource.priority,
                    "Fallback explosion audio should use the same baseline priority as explosion one-shots");
                InGameAssert.IsTrue(createdSource.isPlaying,
                    "Fallback explosion audio source should be playing before pause");

                int paused = GhostPlaybackLogic.PauseExplosionOneShotAudio();
                yield return null;
                InGameAssert.IsTrue(paused >= 1,
                    "PauseExplosionOneShotAudio should pause the independent fallback source");
                InGameAssert.IsFalse(createdSource.isPlaying,
                    "Fallback explosion audio source should stop playing while paused");

                int unpaused = GhostPlaybackLogic.UnpauseExplosionOneShotAudio();
                yield return null;
                InGameAssert.IsTrue(unpaused >= 1,
                    "UnpauseExplosionOneShotAudio should resume the independent fallback source");
                InGameAssert.IsTrue(createdSource.isPlaying,
                    "Fallback explosion audio source should resume after unpause");

                UnityEngine.Object.Destroy(ghostRoot);
                yield return null;
                InGameAssert.IsTrue(createdSource != null,
                    "Fallback explosion audio source should survive immediate ghost destruction");
            }
            finally
            {
                if (clip != null)
                    UnityEngine.Object.Destroy(clip);
                GhostPlaybackLogic.ResetForTesting();
            }
        }

