        private static IEnumerator WaitForMissionControl(float timeoutSeconds)
        {
            yield return WaitUntilTrue(
                () => Object.FindObjectOfType<MissionControl>() != null,
                "MissionControl should exist after opening Mission Control",
                timeoutSeconds);
        }

        // Space-center building canvases tear down a frame or more after the close
        // event fires. The overlay tests open the same building repeatedly across
        // cycles and across two suite passes; if a test enters before the prior
        // canvas is gone, UIMasterController refuses to spawn a duplicate
        // ("Canvas named 'X' already exists") and the building UI ends up empty or
        // stacked. These guards drain a stale canvas before entering and confirm
        // the canvas is gone after closing, so each test leaves a clean scene.
        private static IEnumerator WaitForRdControllerClosed(float timeoutSeconds)
        {
            yield return WaitUntilTrue(
                () => RDController.Instance == null && Object.FindObjectOfType<RDController>() == null,
                "RDController canvas should be destroyed after closing R&D",
                timeoutSeconds);
        }

        private static IEnumerator WaitForAstronautComplexClosed(float timeoutSeconds)
        {
            yield return WaitUntilTrue(
                () => Object.FindObjectOfType<AstronautComplex>() == null,
                "AstronautComplex canvas should be destroyed after closing the Astronaut Complex",
                timeoutSeconds);
        }

        private static IEnumerator WaitForMissionControlClosed(float timeoutSeconds)
        {
            yield return WaitUntilTrue(
                () => Object.FindObjectOfType<MissionControl>() == null,
                "MissionControl canvas should be destroyed after closing Mission Control",
                timeoutSeconds);
        }

        private static IEnumerator WaitUntilTrue(
            System.Func<bool> predicate,
            string failureMessage,
            float timeoutSeconds)
        {
            // Use wall-clock time, not Time.time: every caller is a facility/overlay wait,
            // and EnterBuilding pauses the game (FlightDriver.SetPause -> timeScale 0), which
            // freezes Time.time. A Time.time deadline would never expire while a facility is
            // open, so a failed close would hang the suite forever instead of timing out.
            float deadline = Time.realtimeSinceStartup + timeoutSeconds;
            while (Time.realtimeSinceStartup < deadline)
            {
                if (predicate())
                    yield break;
                yield return null;
            }

            InGameAssert.Fail($"{failureMessage} (timed out after {timeoutSeconds:F1}s)");
        }

        private static bool TryPickRdNode(
            RDController controller,
            out RDNode node,
            out string techId,
            out string reason)
        {
            node = null;
            techId = null;
            reason = null;

            List<RDNode> nodes;
            if (!TryGetRuntimeRdNodes(controller, out nodes))
            {
                reason = "RDController.nodes reflection lookup failed";
                return false;
            }

            for (int i = 0; i < nodes.Count; i++)
            {
                RDNode candidate = nodes[i];
                if (candidate == null || candidate.transform == null || candidate.tech == null)
                    continue;
                if (string.IsNullOrEmpty(candidate.tech.techID))
                    continue;

                node = candidate;
                techId = candidate.tech.techID;
                return true;
            }

            reason = "No RDNode with a non-empty tech.techID was available";
            return false;
        }

        private static bool TryGetRuntimeRdNodes(RDController controller, out List<RDNode> nodes)
        {
            nodes = null;
            controller = controller ?? RDController.Instance ?? Object.FindObjectOfType<RDController>();
            if (controller == null)
                return false;

            FieldInfo field = typeof(RDController).GetField(
                "nodes",
                BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic);
            nodes = field != null ? field.GetValue(controller) as List<RDNode> : null;
            return nodes != null;
        }

        private static Recording AddCommittedOverlayFixture(
            string recordingId,
            GameStateEventType eventType,
            string key,
            string detail)
        {
            double now = Planetarium.GetUniversalTime();
            var recording = new Recording
            {
                RecordingId = recordingId,
                VesselName = "Phase 5 Stock UI Overlay Test",
                ExplicitStartUT = now - 1.0,
                ExplicitEndUT = now + 120.0,
                MergeState = MergeState.Immutable
            };
            // Intentional no-tree fixture: these overlay tests only need recording lookup for tooltip context.
            RecordingStore.AddCommittedInternal(recording);

            var evt = new GameStateEvent
            {
                ut = now + 60.0,
                eventType = eventType,
                key = key,
                detail = detail ?? "",
                recordingId = recordingId,
                epoch = 0u
            };
            var milestone = new Milestone
            {
                MilestoneId = "phase5-overlay-" + System.Guid.NewGuid().ToString("N"),
                StartUT = evt.ut,
                EndUT = evt.ut,
                RecordingId = recordingId,
                Epoch = 0u,
                Committed = true,
                LastReplayedEventIndex = -1,
                Events = new List<GameStateEvent> { evt }
            };
            MilestoneStore.AddMilestoneForTesting(milestone);
            return recording;
        }

        private static void RemoveCommittedOverlayFixture(string recordingId, Recording recording)
        {
            if (!string.IsNullOrEmpty(recordingId))
            {
                MilestoneStore.PurgeTaggedEvents(
                    new HashSet<string> { recordingId },
                    "phase5-stock-ui-overlay-test");
            }
            if (recording != null)
                RecordingStore.RemoveCommittedInternal(recording);
        }

        private static void NotifyTimelineDataChangedForOverlayTest()
        {
            LedgerOrchestrator.OnTimelineDataChanged?.Invoke();
        }

        // The stock facility close path is firing the matching despawn GameEvent —
        // that is exactly what UISpaceCenter's exit button / Escape handler does, and
        // UISpaceCenter listens to it for FlightDriver.UnPause + canvas teardown, while
        // the facility's own (privately-registered) onDialogClose handler runs as
        // another listener of the same event. Do NOT gate this on building.IsOpen():
        // those overrides are always-true mode/instance gates, and invoking the private
        // onDialogClose directly is a no-op for closing (it only deregisters handlers and
        // clears a control lock, leaving the canvas up and the game paused — which made
        // the overlay tests hang until manually exited).
        private static void CloseRnDForOverlayTest(RDController controller)
        {
            try
            {
                controller = controller ?? RDController.Instance ?? Object.FindObjectOfType<RDController>();
                if (controller != null)
                    RDController.OnRDTreeDespawn.Fire(controller);
                GameEvents.onGUIRnDComplexDespawn.Fire();
            }
            catch (System.Exception ex)
            {
                ParsekLog.Warn("TestRunner", $"Phase 5 R&D overlay close helper threw: {ex}");
            }
        }

        private static void CloseAstronautForOverlayTest()
        {
            try
            {
                GameEvents.onGUIAstronautComplexDespawn.Fire();
            }
            catch (System.Exception ex)
            {
                ParsekLog.Warn("TestRunner", $"Phase 5 Astronaut overlay close helper threw: {ex}");
            }
        }

        private static void CloseMissionControlForOverlayTest()
        {
            try
            {
                GameEvents.onGUIMissionControlDespawn.Fire();
            }
            catch (System.Exception ex)
            {
                ParsekLog.Warn("TestRunner", $"Phase 5 MissionControl overlay close helper threw: {ex}");
            }
        }

        private static IEnumerator WaitForNamedChildCount(
            Transform root,
            string childName,
            int expected,
            string failureMessage,
            float timeoutSeconds)
        {
            yield return WaitUntilTrue(
                () => CountNamedChildren(root, childName) == expected,
                $"{failureMessage}; expected={expected} actual={CountNamedChildren(root, childName)}",
                timeoutSeconds);
        }

        private static IEnumerator WaitForGlobalOverlayCount(
            string objectName,
            int expected,
            string failureMessage,
            float timeoutSeconds)
        {
            yield return WaitUntilTrue(
                () => CountGlobalNamedTransforms(objectName) == expected,
                $"{failureMessage}; expected={expected} actual={CountGlobalNamedTransforms(objectName)}",
                timeoutSeconds);
        }

        private static int CountNamedChildren(Transform root, string childName)
        {
            if (root == null || string.IsNullOrEmpty(childName))
                return 0;

            int count = 0;
            Transform[] children = root.GetComponentsInChildren<Transform>(true);
            for (int i = 0; i < children.Length; i++)
            {
                Transform child = children[i];
                if (child != null && child.gameObject != null && child.gameObject.name == childName)
                    count++;
            }

            return count;
        }

        private static int CountGlobalNamedTransforms(string objectName)
        {
            int count = 0;
            Transform[] all = Resources.FindObjectsOfTypeAll<Transform>();
            for (int i = 0; i < all.Length; i++)
            {
                Transform transform = all[i];
                if (transform != null && transform.gameObject != null && transform.gameObject.name == objectName)
                    count++;
            }

            return count;
        }

        private static ProtoCrewMember CreateApplicantForOverlayTest(KerbalRoster roster, string name)
        {
            ProtoCrewMember applicant = roster.GetNewKerbal(ProtoCrewMember.KerbalType.Applicant);
            InGameAssert.IsNotNull(applicant, $"Could not create applicant '{name}' for Astronaut overlay test");
            applicant.ChangeName(name);
            applicant.rosterStatus = ProtoCrewMember.RosterStatus.Available;
            return applicant;
        }

        private static bool TryInstallReservedKerbalForOverlayTest(KerbalsModule module, string name)
        {
            FieldInfo field = typeof(KerbalsModule).GetField(
                "reservations",
                BindingFlags.Instance | BindingFlags.NonPublic);
            if (field == null)
            {
                InGameAssert.Skip("KerbalsModule.reservations field missing; cannot install reserved applicant fixture");
                return false;
            }

            field.SetValue(module, new Dictionary<string, KerbalsModule.KerbalReservation>
            {
                [name] = new KerbalsModule.KerbalReservation
                {
                    KerbalName = name,
                    ReservedUntilUT = double.PositiveInfinity,
                    IsPermanent = false
                }
            });
            return true;
        }

        private static void RemoveKerbalForOverlayTest(KerbalRoster roster, ProtoCrewMember member)
        {
            if (roster == null || member == null)
                return;

            try
            {
                roster.Remove(member);
            }
            catch (System.Exception ex)
            {
                ParsekLog.Warn("TestRunner",
                    $"Phase 5 Astronaut overlay applicant cleanup failed for '{member.name}': {ex}");
            }
        }

        private static IEnumerator WaitForCrewListItemOverlay(
            string kerbalName,
            string overlayName,
            string failureMessage,
            float timeoutSeconds)
        {
            float deadline = Time.time + timeoutSeconds;
            while (Time.time < deadline)
            {
                CrewListItem row = FindCrewListItemByName(Object.FindObjectOfType<AstronautComplex>(), kerbalName);
                if (row != null && CountNamedChildren(row.transform, overlayName) == 1)
                    yield break;
                yield return null;
            }

            CrewListItem finalRow = FindCrewListItemByName(Object.FindObjectOfType<AstronautComplex>(), kerbalName);
            int actual = finalRow != null ? CountNamedChildren(finalRow.transform, overlayName) : -1;
            InGameAssert.Fail($"{failureMessage}; rowFound={finalRow != null} overlayCount={actual}");
        }

        private static CrewListItem FindCrewListItemByName(AstronautComplex complex, string name)
        {
            if (complex == null || string.IsNullOrEmpty(name))
                return null;

            CrewListItem[] items = complex.GetComponentsInChildren<CrewListItem>(true);
            for (int i = 0; i < items.Length; i++)
            {
                CrewListItem item = items[i];
                if (item == null)
                    continue;

                try
                {
                    if (string.Equals(item.GetName(), name, System.StringComparison.Ordinal))
                        return item;
                }
                catch (System.Exception ex)
                {
                    ParsekLog.VerboseRateLimited("TestRunner", "phase5-crew-row-name-failed",
                        $"Phase 5 CrewListItem.GetName failed while searching for '{name}': {ex.Message}");
                }
            }

            return null;
        }

        private sealed class MissionControlContractRowPick
        {
            internal bool Found;
            internal Contract Contract;
            internal string ContractKey;
            internal string ContractTitle;
            internal string SkipReason;
        }

        private static IEnumerator WaitForMissionControlOfferedContractRow(
            MissionControlContractRowPick result,
            float timeoutSeconds)
        {
            InGameAssert.IsNotNull(result, "Mission Control contract row result holder is required");
            float deadline = Time.time + timeoutSeconds;
            string lastSkipReason = null;

            while (Time.time < deadline)
            {
                MissionControl missionControl = Object.FindObjectOfType<MissionControl>();
                if (TryPickMissionControlOfferedContractRow(
                        missionControl,
                        out Contract contract,
                        out string contractKey,
                        out string contractTitle,
                        out lastSkipReason))
                {
                    result.Found = true;
                    result.Contract = contract;
                    result.ContractKey = contractKey;
                    result.ContractTitle = contractTitle;
                    result.SkipReason = null;
                    yield break;
                }

                yield return null;
            }

            MissionControl finalMissionControl = Object.FindObjectOfType<MissionControl>();
            if (TryPickMissionControlOfferedContractRow(
                    finalMissionControl,
                    out Contract finalContract,
                    out string finalContractKey,
                    out string finalContractTitle,
                    out string finalSkipReason))
            {
                result.Found = true;
                result.Contract = finalContract;
                result.ContractKey = finalContractKey;
                result.ContractTitle = finalContractTitle;
                result.SkipReason = null;
                yield break;
            }

            result.Found = false;
            result.Contract = null;
            result.ContractKey = null;
            result.ContractTitle = null;
            result.SkipReason = finalSkipReason ?? lastSkipReason ?? "Mission Control offered contract row did not appear";
        }

        private static bool TryPickMissionControlOfferedContractRow(
            MissionControl missionControl,
            out Contract contract,
            out string contractKey,
            out string contractTitle,
            out string skipReason)
        {
            contract = null;
            contractKey = null;
            contractTitle = null;
            skipReason = null;

            if (missionControl == null)
            {
                skipReason = "MissionControl is not open";
                return false;
            }

            MCListItem[] rows = missionControl.GetComponentsInChildren<MCListItem>(true);
            int rowCount = rows != null ? rows.Length : 0;
            int contractRowCount = 0;
            int offeredRowCount = 0;
            int activeRowCount = 0;
            for (int i = 0; i < rowCount; i++)
            {
                MCListItem row = rows[i];
                if (row == null)
                    continue;

                Contract candidate = ExtractMissionControlRowContractForTest(row);
                if (candidate == null)
                    continue;
                contractRowCount++;

                if (candidate.ContractState == Contract.State.Active)
                    activeRowCount++;
                if (candidate.ContractState != Contract.State.Offered)
                    continue;
                offeredRowCount++;

                string key = candidate.ContractGuid.ToString();
                string title = candidate.Title;
                if (string.IsNullOrEmpty(key) || string.IsNullOrEmpty(title))
                    continue;

                contract = candidate;
                contractKey = key;
                contractTitle = title;
                return true;
            }

            skipReason =
                "No Mission Control offered contract row with a non-empty title/Guid is available " +
                $"(rows={rowCount}, contractRows={contractRowCount}, offeredRows={offeredRowCount}, activeRows={activeRowCount})";
            return false;
        }

        private static IEnumerator WaitForMissionControlRowOverlay(
            string contractKey,
            string overlayName,
            string failureMessage,
            float timeoutSeconds)
        {
            float deadline = Time.time + timeoutSeconds;
            while (Time.time < deadline)
            {
                MCListItem row = FindMissionControlRowByContractKey(Object.FindObjectOfType<MissionControl>(), contractKey);
                if (row != null && CountNamedChildren(row.transform, overlayName) == 1)
                    yield break;
                yield return null;
            }

            MCListItem finalRow = FindMissionControlRowByContractKey(Object.FindObjectOfType<MissionControl>(), contractKey);
            int actual = finalRow != null ? CountNamedChildren(finalRow.transform, overlayName) : -1;
            InGameAssert.Fail($"{failureMessage}; rowFound={finalRow != null} overlayCount={actual}");
        }

        private static MCListItem FindMissionControlRowByContractKey(MissionControl missionControl, string contractKey)
        {
            if (missionControl == null || string.IsNullOrEmpty(contractKey))
                return null;

            MCListItem[] rows = missionControl.GetComponentsInChildren<MCListItem>(true);
            for (int i = 0; i < rows.Length; i++)
            {
                MCListItem row = rows[i];
                if (row == null)
                    continue;

                if (string.Equals(ExtractMissionControlRowContractKeyForTest(row), contractKey, System.StringComparison.Ordinal))
                    return row;
            }

            return null;
        }

        private static string ExtractMissionControlRowContractKeyForTest(MCListItem row)
        {
            Contract contract = ExtractMissionControlRowContractForTest(row);
            return contract != null ? contract.ContractGuid.ToString() : null;
        }

        private static Contract ExtractMissionControlRowContractForTest(MCListItem row)
        {
            try
            {
                return row != null && row.container != null
                    ? row.container.Data as Contract
                    : null;
            }
            catch (System.Exception ex)
            {
                ParsekLog.VerboseRateLimited("TestRunner", "phase5-mission-row-contract-key-failed",
                    $"Phase 5 MissionControl row contract-key lookup failed: {ex.Message}");
                return null;
            }
        }

