        [InGameTest(Category = "GhostPlayback", Scene = GameScenes.FLIGHT,
            Description = "v13 loop-chain debris with missing live anchor: falls back to body-fixed primary (does not retire)")]
        public void V13Debris_LoopChain_LiveAnchorMissing_FallsBackToBodyFixed()
        {
            // The loop-anchored tree references pid=77; no live vessel with that
            // pid is registered, so the live anchor cannot resolve. The engine
            // must fall back to body-fixed primary rather than retiring.
            var scenario = RunV13DebrisFrameScenario(
                loopAnchoredParent: true,
                includeBodyFixedPrimary: true,
                currentUT: 2.5);

            // Either the relative resolver fails closed and engine falls back to
            // body-fixed primary, or the relative path runs and uses the recorded
            // anchor frames. Either way the ghost must stay visible and not
            // retire.
            InGameAssert.IsTrue(scenario.state.ghost.activeSelf,
                "missing live anchor must not retire a loop-chain debris when body-fixed primary covers the frame");
            InGameAssert.IsFalse(scenario.state.anchorRetiredThisFrame,
                "missing live anchor must not set the frame-local retire flag when body-fixed primary covers the frame");
            InGameAssert.IsTrue(
                scenario.positioner.BodyFixedCalls + scenario.positioner.RelativeCalls >= 1,
                "either body-fixed primary or recorded relative must be invoked - retirement is the failure mode");
        }

        [InGameTest(Category = "GhostPlayback", Scene = GameScenes.FLIGHT,
            Description = "v13 close-range debris with non-loop parent: body-fixed primary path is invariant under repeated frames (cadence-proportional render stability)")]
        public void V13Debris_CloseRange_BodyFixedPrimaryStableAcrossFrames()
        {
            // The §7.4 'cadence proportional to density' test ultimately reduces
            // to: at close range, repeated render calls keep dispatching through
            // body-fixed primary deterministically, regardless of frame count.
            var activeVessel = FlightGlobals.ActiveVessel;
            if (activeVessel == null || activeVessel.mainBody == null)
                InGameAssert.Skip("needs an active vessel with a main body");

            var positioner = new V13DebrisRuntimePositioner();
            var engine = new GhostPlaybackEngine(positioner);
            engine.ResolvePlaybackDistanceOverride =
                (recordingIndex, playbackTrajectory, ghostState, playbackUT) => 0.0;
            engine.ResolvePlaybackActiveVesselDistanceOverride =
                (recordingIndex, playbackTrajectory, ghostState, playbackUT) => 0.0;

            GameObject ghost = new GameObject("ParsekTestGhost_V13CadenceStable");
            runner.TrackForCleanup(ghost);
            ghost.SetActive(true);
            var state = new GhostPlaybackState
            {
                vesselName = "V13 Cadence Stable Debris",
                ghost = ghost,
                playbackIndex = 0,
                initialRelativeActivationHiddenPrimed = true,
                initialRelativeActivationHiddenFramesRemaining = 0,
            };
            engine.ghostStates[0] = state;

            Recording rec = MakeV13DebrisRuntimeRecording(
                recordingId: "v13-cadence-debris",
                parentRecordingId: "v13-cadence-parent",
                bodyName: activeVessel.mainBody.name,
                includeBodyFixedPrimary: true,
                includeAbsoluteTail: false);

            for (int i = 0; i < 5; i++)
            {
                RunV13DebrisUpdate(engine, rec, currentUT: 1.0 + i * 0.5);
            }

            InGameAssert.AreEqual(5, positioner.BodyFixedCalls,
                "every close-range Relative-section render call must dispatch through body-fixed primary");
            InGameAssert.AreEqual(0, positioner.RelativeCalls,
                "close-range non-loop debris must never invoke the Relative route");
            InGameAssert.AreEqual(0, positioner.AbsoluteCalls,
                "close-range debris (no Absolute tail) must never invoke the absolute positioner");
            InGameAssert.IsTrue(state.ghost.activeSelf,
                "close-range debris must stay visible across repeated frames");
        }

        private (GhostPlaybackState state, V13DebrisRuntimePositioner positioner)
            RunV13DebrisFrameScenario(
                bool loopAnchoredParent,
                bool includeBodyFixedPrimary,
                double currentUT)
        {
            var activeVessel = FlightGlobals.ActiveVessel;
            if (activeVessel == null || activeVessel.mainBody == null)
                InGameAssert.Skip("needs an active vessel with a main body");

            var positioner = new V13DebrisRuntimePositioner();
            var engine = new GhostPlaybackEngine(positioner);
            engine.ResolvePlaybackDistanceOverride =
                (recordingIndex, playbackTrajectory, ghostState, playbackUT) => 0.0;
            engine.ResolvePlaybackActiveVesselDistanceOverride =
                (recordingIndex, playbackTrajectory, ghostState, playbackUT) => 0.0;

            GameObject ghost = new GameObject(loopAnchoredParent
                ? "ParsekTestGhost_V13LoopDebris"
                : "ParsekTestGhost_V13Debris");
            runner.TrackForCleanup(ghost);
            ghost.SetActive(true);
            var state = new GhostPlaybackState
            {
                vesselName = loopAnchoredParent ? "V13 Loop Debris" : "V13 Debris",
                ghost = ghost,
                playbackIndex = 0,
                initialRelativeActivationHiddenPrimed = true,
                initialRelativeActivationHiddenFramesRemaining = 0,
            };
            engine.ghostStates[0] = state;

            string parentId = loopAnchoredParent
                ? "v13-loop-parent"
                : "v13-parent";
            Recording rec = MakeV13DebrisRuntimeRecording(
                recordingId: loopAnchoredParent ? "v13-loop-debris" : "v13-debris",
                parentRecordingId: parentId,
                bodyName: activeVessel.mainBody.name,
                includeBodyFixedPrimary: includeBodyFixedPrimary,
                includeAbsoluteTail: false);
            RecordingTree tree = null;
            if (loopAnchoredParent)
            {
                tree = MakeV13LoopAnchoredRuntimeTree(rec, parentId);
                RecordingStore.AddCommittedTreeForTesting(tree);
            }

            try
            {
                RunV13DebrisUpdate(engine, rec, currentUT);
            }
            finally
            {
                if (tree != null)
                    RecordingStore.RemoveCommittedTreeById(tree.Id, "v13-runtime-test-cleanup");
            }

            return (state, positioner);
        }

        private static void RunV13DebrisUpdate(
            GhostPlaybackEngine engine,
            Recording rec,
            double currentUT,
            float warpRate = 1f)
        {
            var flags = new[]
            {
                new TrajectoryPlaybackFlags
                {
                    chainEndUT = rec.EndUT,
                    recordingId = rec.RecordingId,
                    segmentLabel = rec.VesselName,
                },
            };
            var ctx = new FrameContext
            {
                currentUT = currentUT,
                warpRate = warpRate,
                warpRateIndex = warpRate > 1f ? 1 : 0,
                activeVesselPos = Vector3d.zero,
                protectedIndex = -1,
                protectedLoopCycleIndex = -1,
                externalGhostCount = 0,
                mapViewEnabled = false,
                autoLoopIntervalSeconds = 10.0,
            };
            engine.UpdatePlayback(new IPlaybackTrajectory[] { rec }, flags, ctx);
        }

        private static Recording MakeV13DebrisRuntimeRecording(
            string recordingId,
            string parentRecordingId,
            string bodyName,
            bool includeBodyFixedPrimary,
            bool includeAbsoluteTail)
        {
            var relativeFrames = new List<TrajectoryPoint>
            {
                MakeV13RuntimePoint(0.0, bodyName, 1.0),
                MakeV13RuntimePoint(5.0, bodyName, 2.0),
            };
            var section = new TrackSection
            {
                referenceFrame = ReferenceFrame.Relative,
                startUT = 0.0,
                endUT = includeAbsoluteTail ? 2.5 : 5.0,
                anchorRecordingId = parentRecordingId,
                frames = relativeFrames,
                bodyFixedFrames = includeBodyFixedPrimary
                    ? new List<TrajectoryPoint>
                    {
                        MakeV13RuntimePoint(0.0, bodyName, 0.0),
                        MakeV13RuntimePoint(includeAbsoluteTail ? 2.5 : 5.0, bodyName, 50.0),
                    }
                    : new List<TrajectoryPoint>(),
            };
            var rec = new Recording
            {
                RecordingId = recordingId,
                RecordingFormatVersion = RecordingStore.CurrentRecordingFormatVersion,
                VesselName = recordingId,
                PlaybackEnabled = true,
                IsDebris = true,
                ParentAnchorRecordingId = parentRecordingId,
                Points = new List<TrajectoryPoint>(relativeFrames),
                TrackSections = new List<TrackSection> { section },
            };
            if (includeAbsoluteTail)
            {
                var absoluteSection = new TrackSection
                {
                    referenceFrame = ReferenceFrame.Absolute,
                    startUT = 2.5,
                    endUT = 5.0,
                    frames = new List<TrajectoryPoint>
                    {
                        MakeV13RuntimePoint(2.5, bodyName, 50.0),
                        MakeV13RuntimePoint(5.0, bodyName, 60.0),
                    },
                };
                rec.TrackSections.Add(absoluteSection);
                rec.Points.AddRange(absoluteSection.frames);
            }
            return rec;
        }

        private static RecordingTree MakeV13LoopAnchoredRuntimeTree(
            Recording child,
            string parentRecordingId)
        {
            uint loopAnchorPid = 77u;
            var parent = new Recording
            {
                RecordingId = parentRecordingId,
                RecordingFormatVersion = RecordingStore.CurrentRecordingFormatVersion,
                TreeId = "v13-runtime-loop-tree",
                VesselName = parentRecordingId,
                LoopPlayback = true,
                LoopAnchorVesselId = loopAnchorPid,
                TrackSections = new List<TrackSection>
                {
                    new TrackSection
                    {
                        referenceFrame = ReferenceFrame.Relative,
                        startUT = 0.0,
                        endUT = 5.0,
                        anchorVesselId = loopAnchorPid,
                        frames = new List<TrajectoryPoint>
                        {
                            MakeV13RuntimePoint(0.0, child.Points[0].bodyName, 100.0),
                            MakeV13RuntimePoint(5.0, child.Points[0].bodyName, 110.0),
                        },
                    },
                },
            };
            child.TreeId = parent.TreeId;
            var tree = new RecordingTree
            {
                Id = parent.TreeId,
                TreeName = "v13 runtime loop tree",
                RootRecordingId = parent.RecordingId,
                ActiveRecordingId = child.RecordingId,
            };
            tree.AddOrReplaceRecording(parent);
            tree.AddOrReplaceRecording(child);
            return tree;
        }

        private static TrajectoryPoint MakeV13RuntimePoint(
            double ut,
            string bodyName,
            double x)
        {
            return new TrajectoryPoint
            {
                ut = ut,
                bodyName = bodyName,
                latitude = x,
                longitude = 0.0,
                altitude = 0.0,
                rotation = Quaternion.identity,
                velocity = Vector3.zero,
            };
        }

        [InGameTest(Category = "GhostPlayback", Scene = GameScenes.FLIGHT,
            Description = "#613 finalize-spawn retire gate: fresh LoopEnter and OverlapPrimaryEnter spawns into an unresolved relative section must not emit RetargetToNewGhost from the hidden origin-positioned pivot")]
        public void Bug613_FreshSpawnIntoUnresolvedRelativeSection_NoRetargetAtOrigin()
        {
            var loop = RunBug613FreshSpawnRetargetScenario(
                positionerSetsRetireFlag: true,
                overlapPrimary: false);
            var overlap = RunBug613FreshSpawnRetargetScenario(
                positionerSetsRetireFlag: true,
                overlapPrimary: true);

            InGameAssert.AreEqual(0, loop.loopEvents.Count,
                "LoopEnter fresh spawn must suppress RetargetToNewGhost when relative priming retired the anchor");
            InGameAssert.AreEqual(0, overlap.overlapEvents.Count,
                "OverlapPrimaryEnter fresh spawn must suppress RetargetToNewGhost when relative priming retired the anchor");
            InGameAssert.AreEqual(1, loop.createdEvents.Count,
                "LoopEnter spawn lifecycle must still fire OnGhostCreated; only the camera retarget side effect is suppressed");
            InGameAssert.AreEqual(1, overlap.createdEvents.Count,
                "OverlapPrimaryEnter spawn lifecycle must still fire OnGhostCreated; only the camera retarget side effect is suppressed");
            InGameAssert.AreEqual(PendingSpawnLifecycle.None, loop.state.pendingSpawnLifecycle,
                "LoopEnter pending lifecycle must complete even when the retarget side effect is suppressed");
            InGameAssert.AreEqual(PendingSpawnLifecycle.None, overlap.state.pendingSpawnLifecycle,
                "OverlapPrimaryEnter pending lifecycle must complete even when the retarget side effect is suppressed");
            InGameAssert.IsTrue(loop.positioner.RelativeCalls >= 1,
                "LoopEnter fresh-spawn priming must exercise the relative positioner so the retire flag was meaningful");
            InGameAssert.IsTrue(overlap.positioner.RelativeCalls >= 1,
                "OverlapPrimaryEnter fresh-spawn priming must exercise the relative positioner so the retire flag was meaningful");
            InGameAssert.IsTrue(loop.capturedLog.Any(l =>
                    l.Contains("[Engine]")
                    && l.Contains("finalize-spawn retire: suppressing RetargetToNewGhost")
                    && l.Contains("anchor retired on first spawn")
                    && l.Contains("lifecycle=LoopEnter")),
                "LoopEnter retired fresh spawn must emit the finalize-spawn retire suppression log");
            InGameAssert.IsTrue(overlap.capturedLog.Any(l =>
                    l.Contains("[Engine]")
                    && l.Contains("finalize-spawn retire: suppressing RetargetToNewGhost")
                    && l.Contains("anchor retired on first spawn")
                    && l.Contains("lifecycle=OverlapPrimaryEnter")),
                "OverlapPrimaryEnter retired fresh spawn must emit the finalize-spawn retire suppression log");
        }

        [InGameTest(Category = "GhostPlayback", Scene = GameScenes.FLIGHT,
            Description = "#613 finalize-spawn retire gate negative: fresh LoopEnter and OverlapPrimaryEnter spawns with a resolved relative anchor still emit RetargetToNewGhost")]
        public void Bug613_FreshSpawnWithResolvedAnchor_StillFiresRetarget()
        {
            var loop = RunBug613FreshSpawnRetargetScenario(
                positionerSetsRetireFlag: false,
                overlapPrimary: false);
            var overlap = RunBug613FreshSpawnRetargetScenario(
                positionerSetsRetireFlag: false,
                overlapPrimary: true);

            InGameAssert.AreEqual(1, loop.loopEvents.Count,
                "LoopEnter resolved fresh spawn must still emit one RetargetToNewGhost event");
            InGameAssert.AreEqual(1, overlap.overlapEvents.Count,
                "OverlapPrimaryEnter resolved fresh spawn must still emit one RetargetToNewGhost event");
            InGameAssert.IsTrue(loop.loopEvents[0].Action == CameraActionType.RetargetToNewGhost,
                "LoopEnter resolved fresh spawn must emit the RetargetToNewGhost action");
            InGameAssert.IsTrue(overlap.overlapEvents[0].Action == CameraActionType.RetargetToNewGhost,
                "OverlapPrimaryEnter resolved fresh spawn must emit the RetargetToNewGhost action");
            InGameAssert.IsNotNull(loop.state.cameraPivot,
                "LoopEnter resolved fresh spawn must create the camera pivot before retargeting");
            InGameAssert.IsNotNull(overlap.state.cameraPivot,
                "OverlapPrimaryEnter resolved fresh spawn must create the camera pivot before retargeting");
            InGameAssert.IsTrue(ReferenceEquals(loop.state.cameraPivot, loop.loopEvents[0].GhostPivot),
                "LoopEnter RetargetToNewGhost must carry the spawned state's camera pivot");
            InGameAssert.IsTrue(ReferenceEquals(overlap.state.cameraPivot, overlap.overlapEvents[0].GhostPivot),
                "OverlapPrimaryEnter RetargetToNewGhost must carry the spawned state's camera pivot");
            InGameAssert.AreEqual(1, loop.createdEvents.Count,
                "LoopEnter resolved fresh spawn must still fire OnGhostCreated once");
            InGameAssert.AreEqual(1, overlap.createdEvents.Count,
                "OverlapPrimaryEnter resolved fresh spawn must still fire OnGhostCreated once");
            InGameAssert.IsFalse(loop.capturedLog.Any(l =>
                    l.Contains("finalize-spawn retire: suppressing RetargetToNewGhost")),
                "LoopEnter resolved fresh spawn must not log retire suppression");
            InGameAssert.IsFalse(overlap.capturedLog.Any(l =>
                    l.Contains("finalize-spawn retire: suppressing RetargetToNewGhost")),
                "OverlapPrimaryEnter resolved fresh spawn must not log retire suppression");
        }

        // Scenario harness: builds an engine with a mock IGhostPositioner
        // whose InterpolateAndPositionRelative either does or does not set
        // state.anchorRetiredThisFrame, then drives one UpdatePlayback frame.
        private GhostPlaybackState RunBug613RelativeRetireScenario(
            bool positionerSetsRetireFlag,
            out GameObject ghost,
            out List<string> capturedLog,
            bool preFrameRetireFlag = false)
        {
            var activeVessel = FlightGlobals.ActiveVessel;
            if (activeVessel == null || activeVessel.mainBody == null)
                InGameAssert.Skip("needs an active vessel with a main body");

            var positioner = new Bug613RetireBranchPositioner
            {
                SetsRetireFlag = positionerSetsRetireFlag,
            };
            var engine = new GhostPlaybackEngine(positioner);
            // Force "in range" so RenderInRangeGhost is taken instead of any
            // hidden-by-zone path.
            engine.ResolvePlaybackDistanceOverride =
                (recordingIndex, playbackTrajectory, ghostState, playbackUT) => 0.0;
            engine.ResolvePlaybackActiveVesselDistanceOverride =
                (recordingIndex, playbackTrajectory, ghostState, playbackUT) => 0.0;

            // Use a primitive cube so the ghost has a real MeshRenderer.
            // TrackGhostAppearance gates on TryGetCombinedVisibleRendererBounds
            // walking the part container's child Renderers (with a fallback to
            // the ghost root itself when no GhostVisualsRoot child exists), so
            // a bare `new GameObject(...)` could never satisfy the renderer
            // probe and appearanceCount could never increment — the resolved-
            // anchor variant of this scenario then failed on `appearanceCount
            // >= 1` even though the engine gate it was meant to pin worked
            // correctly. The retired-anchor variant is unaffected because the
            // engine's retire branch skips TrackGhostAppearance entirely.
            // Drop the auto-added Collider so this test does not interact with
            // KSP's physics scene.
            ghost = GameObject.CreatePrimitive(PrimitiveType.Cube);
            ghost.name = positionerSetsRetireFlag
                ? "ParsekTestGhost_Bug613Retired"
                : "ParsekTestGhost_Bug613Resolved";
            var ghostCollider = ghost.GetComponent<Collider>();
            if (ghostCollider != null)
                UnityEngine.Object.Destroy(ghostCollider);
            runner.TrackForCleanup(ghost);
            // Start ACTIVE so a successful retire actually has to flip
            // SetActive from true -> false (matches the production scene
            // where the ghost was just spawned and therefore active).
            ghost.SetActive(true);

            var state = new GhostPlaybackState
            {
                vesselName = "Bug613TestGhost",
                ghost = ghost,
                loopCycleIndex = 0,
                playbackIndex = 0,
                partEventIndex = 0,
                flagEventIndex = 0,
                // Deferred-sync ON so the gate's resolved-path test can
                // verify ActivateGhostVisualsIfNeeded actually flips the
                // flag back to false.
                deferVisibilityUntilPlaybackSync = !positionerSetsRetireFlag,
                anchorRetiredThisFrame = preFrameRetireFlag,
                // Mark the activation-settle priming step as already
                // consumed. Without this, ShouldHoldInitialActivationHiddenThisFrame's
                // `withinActivationSettle` branch (added in commit 64fb617e
                // "Hide watch absolute primer handoffs", May 3) hides the
                // ghost on the very first per-frame render pass because
                // CanEvaluateInitialActivationHidden(traj, state) returns
                // true (deferVisibilityUntilPlaybackSync=true, appearanceCount=0)
                // and the gate's final conjunct
                // !state.initialRelativeActivationHiddenPrimed is also true
                // by default. Production scenes consume the priming step on
                // frame 1 and clear it on frame 2; this test scenario fires
                // only one frame, so we pre-consume here.
                // initialRelativeActivationHiddenFramesRemaining=0 also
                // silences the second `minimum-frames` branch independently
                // (it requires remaining > 0).
                initialRelativeActivationHiddenPrimed = true,
                initialRelativeActivationHiddenFramesRemaining = 0,
            };

            engine.ghostStates[0] = state;

            var traj = new Bug613RelativeTrajectory(
                bodyName: activeVessel.mainBody.name,
                latitude: activeVessel.latitude,
                longitude: activeVessel.longitude,
                altitude: System.Math.Max(0.0, activeVessel.altitude));
            var flags = new[]
            {
                new TrajectoryPlaybackFlags
                {
                    chainEndUT = traj.EndUT,
                    recordingId = traj.RecordingId,
                    segmentLabel = traj.VesselName,
                }
            };

            var ctx = new FrameContext
            {
                currentUT = 2.5,
                warpRate = 1f,
                warpRateIndex = 0,
                activeVesselPos = Vector3d.zero,
                protectedIndex = -1,
                protectedLoopCycleIndex = -1,
                externalGhostCount = 0,
                mapViewEnabled = false,
                autoLoopIntervalSeconds = 10.0,
            };

            var localLog = new List<string>();
            var priorObserver = ParsekLog.TestObserverForTesting;
            var priorVerbose = ParsekLog.VerboseOverrideForTesting;
            ParsekLog.ResetRateLimitsForTesting();
            ParsekLog.VerboseOverrideForTesting = true;
            ParsekLog.TestObserverForTesting = line =>
            {
                localLog.Add(line);
                priorObserver?.Invoke(line);
            };

            try
            {
                engine.UpdatePlayback(
                    new IPlaybackTrajectory[] { traj },
                    flags,
                    ctx);
            }
            finally
            {
                ParsekLog.TestObserverForTesting = priorObserver;
                ParsekLog.VerboseOverrideForTesting = priorVerbose;
            }

            capturedLog = localLog;
            return state;
        }

        private (GhostPlaybackEngine engine,
                 GhostPlaybackState state,
                 Bug613RetireBranchPositioner positioner,
                 List<CameraActionEvent> loopEvents,
                 List<CameraActionEvent> overlapEvents,
                 List<GhostLifecycleEvent> createdEvents,
                 List<string> capturedLog)
            RunBug613FreshSpawnRetargetScenario(
                bool positionerSetsRetireFlag, bool overlapPrimary)
        {
            var activeVessel = FlightGlobals.ActiveVessel;
            if (activeVessel == null || activeVessel.mainBody == null)
                InGameAssert.Skip("needs an active vessel with a main body");

            var positioner = new Bug613RetireBranchPositioner
            {
                SetsRetireFlag = positionerSetsRetireFlag,
                SetsLoopRetireFlag = false,
            };
            var engine = new GhostPlaybackEngine(positioner);
            engine.ResolvePlaybackDistanceOverride =
                (recordingIndex, playbackTrajectory, ghostState, playbackUT) => 0.0;
            engine.ResolvePlaybackActiveVesselDistanceOverride =
                (recordingIndex, playbackTrajectory, ghostState, playbackUT) => 0.0;

            var loopEvents = new List<CameraActionEvent>();
            var overlapEvents = new List<CameraActionEvent>();
            var createdEvents = new List<GhostLifecycleEvent>();
            engine.OnLoopCameraAction += e => loopEvents.Add(e);
            engine.OnOverlapCameraAction += e => overlapEvents.Add(e);
            engine.OnGhostCreated += e => createdEvents.Add(e);

            // Overlap variant: duration=10s + interval=5s -> IsOverlapLoop(5,10)
            // is true AND 5 >= LoopTiming.MinCycleDuration so ResolveLoopInterval
            // does not clamp the period upward. lastCycle = floor(2.5/5) = 0;
            // primaryState=null => primaryCycleChanged=true => fresh spawn with
            // PendingSpawnLifecycle.OverlapPrimaryEnter.
            //
            // Loop variant: duration=10s + interval=10s -> IsOverlapLoop(10,10)
            // is false so the engine takes the single-ghost loop path. cycle=0,
            // first-spawn lifecycle = PendingSpawnLifecycle.LoopEnter.
            //
            // Earlier (interval=2.0 / duration=5) clamped to interval=5 and
            // IsOverlapLoop(5,5)=false, so the overlap variant silently fell
            // back to LoopEnter and the OverlapPrimaryEnter assertions never
            // exercised the code path they were written to pin.
            double overlapLoopInterval = 5.0;
            double overlapDuration = 10.0;
            double loopInterval = overlapPrimary ? overlapLoopInterval : 10.0;
            double trajDuration = overlapPrimary ? overlapDuration : 10.0;
            var traj = new Bug613LoopRelativeTrajectory(
                bodyName: activeVessel.mainBody.name,
                latitude: activeVessel.latitude,
                longitude: activeVessel.longitude,
                altitude: System.Math.Max(0.0, activeVessel.altitude),
                terminalDestroyed: false,
                loopIntervalSeconds: loopInterval,
                durationSeconds: trajDuration);
            var flags = new[]
            {
                new TrajectoryPlaybackFlags
                {
                    chainEndUT = double.PositiveInfinity,
                    recordingId = traj.RecordingId,
                    segmentLabel = traj.VesselName,
                }
            };

            var ctx = new FrameContext
            {
                currentUT = 2.5,
                warpRate = 1f,
                warpRateIndex = 0,
                activeVesselPos = Vector3d.zero,
                protectedIndex = -1,
                protectedLoopCycleIndex = -1,
                externalGhostCount = 0,
                mapViewEnabled = false,
                autoLoopIntervalSeconds = loopInterval,
            };

            var localLog = new List<string>();
            var priorObserver = ParsekLog.TestObserverForTesting;
            var priorVerbose = ParsekLog.VerboseOverrideForTesting;
            ParsekLog.ResetRateLimitsForTesting();
            ParsekLog.VerboseOverrideForTesting = true;
            ParsekLog.TestObserverForTesting = line =>
            {
                localLog.Add(line);
                priorObserver?.Invoke(line);
            };

            try
            {
                engine.UpdatePlayback(
                    new IPlaybackTrajectory[] { traj },
                    flags,
                    ctx);
            }
            finally
            {
                ParsekLog.TestObserverForTesting = priorObserver;
                ParsekLog.VerboseOverrideForTesting = priorVerbose;
            }

            GhostPlaybackState state;
            InGameAssert.IsTrue(engine.ghostStates.TryGetValue(0, out state),
                "fresh spawn scenario must leave the spawned ghost state in the engine map");
            InGameAssert.IsNotNull(state,
                "fresh spawn scenario must produce a non-null ghost state");
            InGameAssert.IsNotNull(state.ghost,
                "fresh spawn scenario must build ghost visuals so finalize lifecycle can run");
            runner.TrackForCleanup(state.ghost);

            return (engine, state, positioner, loopEvents, overlapEvents, createdEvents, localLog);
        }

        private sealed class V13DebrisRuntimePositioner : IGhostPositioner
        {
            internal int BodyFixedCalls;
            internal int RelativeCalls;
            internal int AbsoluteCalls;

            public void InterpolateAndPosition(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state, double ut, bool suppressFx)
            {
                AbsoluteCalls++;
                int sectionIndex = TrajectoryMath.FindTrackSectionForUT(traj.TrackSections, ut);
                List<TrajectoryPoint> frames = sectionIndex >= 0
                    ? traj.TrackSections[sectionIndex].frames
                    : traj.Points;
                TryPositionFromFrames(frames, ut, state, out _, out _);
            }

            public void InterpolateAndPositionRelative(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state, double ut, bool suppressFx,
                RelativeSectionPlaybackTarget target)
            {
                RelativeCalls++;
                TryPositionFromFrames(target.Section.frames, ut, state, out _, out _);
            }

            public bool TryPositionFromBodyFixedPrimary(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state, double playbackUT, RelativeSectionPlaybackTarget target,
                out double bracketBeforeUT, out double bracketAfterUT)
            {
                BodyFixedCalls++;
                return TryPositionFromFrames(
                    target.Section.bodyFixedFrames,
                    playbackUT,
                    state,
                    out bracketBeforeUT,
                    out bracketAfterUT);
            }

            public void PositionAtPoint(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state, TrajectoryPoint point)
            {
                ApplyPoint(state, point);
            }

            public void PositionAtSurface(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state)
            {
            }

            public void PositionFromOrbit(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state, double ut)
            {
            }

            public void PositionLoop(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state, double ut, bool suppressFx)
            {
                AbsoluteCalls++;
                TryPositionFromFrames(traj.Points, ut, state, out _, out _);
            }

            public bool TryResolveExplosionAnchorPosition(int index,
                IPlaybackTrajectory traj, GhostPlaybackState state, out Vector3 worldPosition)
            {
                worldPosition = state != null && state.ghost != null
                    ? state.ghost.transform.position
                    : Vector3.zero;
                return state != null && state.ghost != null;
            }

            public ZoneRenderingResult ApplyZoneRendering(int index, GhostPlaybackState state,
                IPlaybackTrajectory traj, double distance, double playbackUT, int protectedIndex)
            {
                return new ZoneRenderingResult();
            }

            public void ClearOrbitCache()
            {
            }

            private static bool TryPositionFromFrames(
                List<TrajectoryPoint> frames,
                double ut,
                GhostPlaybackState state,
                out double bracketBeforeUT,
                out double bracketAfterUT)
            {
                bracketBeforeUT = double.NaN;
                bracketAfterUT = double.NaN;
                if (frames == null || frames.Count == 0 || state?.ghost == null)
                    return false;

                TrajectoryPoint before = frames[0];
                TrajectoryPoint after = frames[frames.Count - 1];
                for (int i = 0; i < frames.Count; i++)
                {
                    if (frames[i].ut <= ut)
                        before = frames[i];
                    if (frames[i].ut >= ut)
                    {
                        after = frames[i];
                        break;
                    }
                }

                bracketBeforeUT = before.ut;
                bracketAfterUT = after.ut;
                double span = after.ut - before.ut;
                float t = span > 0.0 ? (float)((ut - before.ut) / span) : 0f;
                var pos = Vector3.Lerp(
                    new Vector3((float)before.latitude, (float)before.longitude, (float)before.altitude),
                    new Vector3((float)after.latitude, (float)after.longitude, (float)after.altitude),
                    t);
                state.ghost.transform.position = pos;
                if (!state.ghost.activeSelf)
                    state.ghost.SetActive(true);
                state.SetInterpolated(new InterpolationResult(Vector3.zero, before.bodyName, before.altitude));
                return true;
            }

            private static void ApplyPoint(GhostPlaybackState state, TrajectoryPoint point)
            {
                if (state?.ghost == null)
                    return;
                state.ghost.transform.position = new Vector3(
                    (float)point.latitude,
                    (float)point.longitude,
                    (float)point.altitude);
                state.SetInterpolated(new InterpolationResult(Vector3.zero, point.bodyName, point.altitude));
            }
        }

        // Mock positioner that mimics ParsekFlight's relative-frame retire
        // branch. When SetsRetireFlag is true, InterpolateAndPositionRelative
        // sets state.ghost.SetActive(false) AND state.anchorRetiredThisFrame=true,
        // exactly as ParsekFlight.InterpolateAndPositionRelative /
        // PositionGhostRelativeAt do at line ~15413 / ~15510 when
        // FindVesselByPid returns null.
        private sealed class Bug613RetireBranchPositioner : IGhostPositioner
        {
            internal bool SetsRetireFlag;
            // PR #594 P1 round 2: loop-endpoint side-effect gates also need
            // to mimic ParsekFlight.PositionLoopGhost's retire branch when
            // the recorded LoopAnchor pid is unresolvable. Independent flag
            // so tests can drive a relative-frame retire without also
            // retiring the loop-endpoint path (and vice-versa).
            internal bool SetsLoopRetireFlag;
            internal int RelativeCalls;
            internal int AbsoluteCalls;
            internal int LoopCalls;

            public void InterpolateAndPosition(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state, double ut, bool suppressFx)
            {
                AbsoluteCalls++;
            }

            public void InterpolateAndPositionRelative(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state, double ut, bool suppressFx,
                RelativeSectionPlaybackTarget target)
            {
                RelativeCalls++;
                if (!SetsRetireFlag || state == null)
                    return;
                if (state.ghost != null && state.ghost.activeSelf)
                    state.ghost.SetActive(false);
                state.anchorRetiredThisFrame = true;
            }

            public bool TryPositionFromBodyFixedPrimary(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state, double playbackUT, RelativeSectionPlaybackTarget target,
                out double bracketBeforeUT, out double bracketAfterUT)
            {
                bracketBeforeUT = double.NaN;
                bracketAfterUT = double.NaN;
                return false;
            }

            public void PositionAtPoint(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state, TrajectoryPoint point) { }
            public void PositionAtSurface(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state) { }
            public void PositionFromOrbit(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state, double ut) { }
            public void PositionLoop(int index, IPlaybackTrajectory traj,
                GhostPlaybackState state, double ut, bool suppressFx)
            {
                LoopCalls++;
                if (!SetsLoopRetireFlag || state == null)
                    return;
                if (state.ghost != null && state.ghost.activeSelf)
                    state.ghost.SetActive(false);
                state.anchorRetiredThisFrame = true;
            }

            public bool TryResolveExplosionAnchorPosition(int index,
                IPlaybackTrajectory traj, GhostPlaybackState state, out Vector3 worldPosition)
            {
                worldPosition = Vector3.zero;
                return false;
            }

            public ZoneRenderingResult ApplyZoneRendering(int index, GhostPlaybackState state,
                IPlaybackTrajectory traj, double distance, double playbackUT, int protectedIndex)
            {
                return new ZoneRenderingResult();
            }

            public void ClearOrbitCache() { }
        }

        // ===================================================================
        // Bug #613 (PR #594 P1 round 2): three additional side-effect bypass
        // paths that ran with stale-transform / stale-ghostActive state when
        // the relative anchor was unresolvable post-rewind:
        //
        //   1. RenderInRangeGhost -> TryHandleEarlyDestroyedDebrisCompletion
        //      (TriggerExplosionIfDestroyed + completion-event queueing)
        //   2. UpdateLoopingPlayback cycle-change endpoint
        //      (TriggerExplosionIfDestroyed + ExplosionHold camera + LoopRestarted)
        //   3. UpdateExpireAndPositionOverlaps overlap-expiry endpoint
        //      (TriggerExplosionIfDestroyed + ExplosionHold camera + OverlapExpired)
        //   4. HandleLoopPauseWindow loop-pause endpoint
        //      (TriggerExplosionIfDestroyed + missing FX teardown for plumes/RCS)
        //
        // Each test pins both the suppression on retired anchors AND the
        // negative case (resolvable anchor still fires the side effects).
        // ===================================================================

        [InGameTest(Category = "GhostPlayback", Scene = GameScenes.FLIGHT,
            Description = "#613 PR #594 P1 round 2: TryHandleEarlyDestroyedDebrisCompletion must NOT fire on a retired-anchor frame — explosionFired stays false, no completion event queues, and the suppression log line emits")]
        public void Bug613_RetireDuringRender_DoesNotFireEarlyDestroyedCompletion()
        {
            var (engine, state, capturedLog) = RunBug613EarlyDebrisScenario(
                positionerSetsRetireFlag: true);

            InGameAssert.IsFalse(state.explosionFired,
                "explosionFired must stay false on a retired frame: TriggerExplosionIfDestroyed runs at the stale (0,0,0) transform from the just-hidden ghost otherwise");
            InGameAssert.AreEqual(0, engine.Bug613TestEarlyDestroyedCount,
                "early-destroyed-debris dedupe set must stay empty on retired frame; otherwise a later resolvable frame would skip the legitimate completion");
            InGameAssert.AreEqual(0, engine.Bug613TestDeferredCompletedCount,
                "no PlaybackCompletedEvent must be queued on a retired frame — host policy would react to a stale-transform completion");
            InGameAssert.IsTrue(capturedLog.Any(l =>
                    l.Contains("[Engine]")
                    && l.Contains("early-completion suppressed")
                    && l.Contains("anchor retired")),
                "expected verbose 'early-completion suppressed: anchor retired' log line for the retired early-debris frame");
        }

        [InGameTest(Category = "GhostPlayback", Scene = GameScenes.FLIGHT,
            Description = "#613 PR #594 P1 round 2 negative: resolvable anchor still fires the early-destroyed-debris completion (explosionFired=true, dedupe set populated, completion event queued)")]
        public void Bug613_ResolvedAnchorFiresEarlyDestroyedCompletion()
        {
            var (engine, state, _) = RunBug613EarlyDebrisScenario(
                positionerSetsRetireFlag: false);

            InGameAssert.IsTrue(state.explosionFired,
                "resolvable-anchor path must run TriggerExplosionIfDestroyed: explosionFired=true after the early-debris frame");
            InGameAssert.AreEqual(1, engine.Bug613TestEarlyDestroyedCount,
                "early-destroyed-debris dedupe set must contain the recording index after the resolvable frame");
            InGameAssert.AreEqual(1, engine.Bug613TestDeferredCompletedCount,
                "exactly one PlaybackCompletedEvent must be queued for the resolvable early-debris frame");
        }

        [InGameTest(Category = "GhostPlayback", Scene = GameScenes.FLIGHT,
            Description = "#613 PR #594 P1 round 2: loop cycle-change endpoint side effects (explosion, ExplosionHold camera, LoopRestarted) must NOT fire when the retire flag is raised by PositionGhostAtLoopEndpoint")]
        public void Bug613_RetireDuringLoopCycleEndpoint_NoExplosionOrCameraRestart()
        {
            var (cameraEvents, restartEvents, capturedLog, state) = RunBug613LoopCycleScenario(
                positionerSetsLoopRetireFlag: true);

            InGameAssert.IsFalse(state.explosionFired,
                "explosionFired must stay false on retired loop endpoint frame");
            InGameAssert.AreEqual(0, cameraEvents.Count,
                "no OnLoopCameraAction with stale (0,0,0) AnchorPosition must emit on retired loop boundary");
            InGameAssert.AreEqual(0, restartEvents.Count,
                "no LoopRestartedEvent with stale (0,0,0) ExplosionPosition must emit on retired loop boundary");
            InGameAssert.IsTrue(capturedLog.Any(l =>
                    l.Contains("[Engine]")
                    && l.Contains("loop endpoint side effects suppressed")
                    && l.Contains("anchor retired")),
                "expected verbose 'loop endpoint side effects suppressed: anchor retired' log line for the loop cycle-change retire frame");
        }

        [InGameTest(Category = "GhostPlayback", Scene = GameScenes.FLIGHT,
            Description = "#613 PR #594 P1 round 2 negative: resolvable LoopAnchor still emits ExplosionHold camera + LoopRestarted on cycle change")]
        public void Bug613_ResolvedAnchorFiresLoopCycleEndpoint()
        {
            var (cameraEvents, restartEvents, _, _) = RunBug613LoopCycleScenario(
                positionerSetsLoopRetireFlag: false);

            InGameAssert.IsTrue(cameraEvents.Count >= 1,
                "resolvable-anchor loop-cycle boundary must still emit OnLoopCameraAction");
            InGameAssert.IsTrue(restartEvents.Count >= 1,
                "resolvable-anchor loop-cycle boundary must still emit LoopRestartedEvent");
        }

        [InGameTest(Category = "GhostPlayback", Scene = GameScenes.FLIGHT,
            Description = "#613 PR #594 P1 round 2: overlap-expiry endpoint side effects (explosion, ExplosionHold camera, OverlapExpired) must NOT fire when the retire flag is raised on the expiring overlap state")]
        public void Bug613_RetireDuringOverlapExpiry_NoExplosionOrCamera()
        {
            var (cameraEvents, expiredEvents, capturedLog, ovState) = RunBug613OverlapExpiryScenario(
                positionerSetsLoopRetireFlag: true);

            InGameAssert.IsFalse(ovState.explosionFired,
                "explosionFired must stay false on retired overlap-expiry frame");
            InGameAssert.AreEqual(0, cameraEvents.Count,
                "no OnOverlapCameraAction with stale (0,0,0) AnchorPosition must emit on retired overlap expiry");
            InGameAssert.AreEqual(0, expiredEvents.Count,
                "no OverlapExpiredEvent with stale ExplosionPosition must emit on retired overlap expiry");
            InGameAssert.IsTrue(capturedLog.Any(l =>
                    l.Contains("[Engine]")
                    && l.Contains("loop endpoint side effects suppressed")
                    && l.Contains("anchor retired")),
                "expected verbose 'loop endpoint side effects suppressed: anchor retired' log line for the overlap-expiry retire frame");
        }

        [InGameTest(Category = "GhostPlayback", Scene = GameScenes.FLIGHT,
            Description = "#613 PR #594 P1 round 2 negative: resolvable LoopAnchor still emits OnOverlapCameraAction + OverlapExpiredEvent on overlap expiry")]
        public void Bug613_ResolvedAnchorFiresOverlapExpiry()
        {
            var (cameraEvents, expiredEvents, _, _) = RunBug613OverlapExpiryScenario(
                positionerSetsLoopRetireFlag: false);

            InGameAssert.IsTrue(cameraEvents.Count >= 1,
                "resolvable-anchor overlap expiry must still emit OnOverlapCameraAction");
            InGameAssert.IsTrue(expiredEvents.Count >= 1,
                "resolvable-anchor overlap expiry must still emit OverlapExpiredEvent");
        }

        [InGameTest(Category = "GhostPlayback", Scene = GameScenes.FLIGHT,
            Description = "#613 PR #594 P1 round 2 + P3: HandleLoopPauseWindow retire branch must (a) suppress the loop-endpoint explosion and (b) call ApplyFrameVisuals(suppressVisualFx:true) for plume/RCS/reentry-FX teardown — HideAllGhostParts only mutes audio")]
        public void Bug613_RetireDuringLoopPause_StopsEngineFx()
        {
            var (state, capturedLog) = RunBug613LoopPauseScenario(
                positionerSetsLoopRetireFlag: true);

            InGameAssert.IsFalse(state.explosionFired,
                "loop-pause retire must skip TriggerExplosionIfDestroyed; otherwise explosion fires from stale (0,0,0)");
            // ApplyFrameVisuals(suppressVisualFx:true) emits a Verbose log
            // through GhostPlaybackLogic.StopAllEngineFx + Reset paths only
            // when there is engine FX to stop. The reliable contract on this
            // test path is the suppression log line. Pin both the
            // ExplosionHold suppression AND the visible expectation that
            // HandleLoopPauseWindow returned without re-activating the ghost.
            InGameAssert.IsTrue(capturedLog.Any(l =>
                    l.Contains("[Engine]")
                    && l.Contains("loop endpoint side effects suppressed")
                    && l.Contains("anchor retired")),
                "expected verbose 'loop endpoint side effects suppressed: anchor retired' log line for the loop-pause retire frame");
            InGameAssert.IsFalse(state.ghost.activeSelf,
                "loop-pause retire frame must end ghost INACTIVE — ApplyFrameVisuals teardown must not flip SetActive(true)");
        }

        [InGameTest(Category = "GhostPlayback", Scene = GameScenes.FLIGHT,
            Description = "#613 PR #594 P1 round 2 negative: resolvable LoopAnchor on loop-pause endpoint still fires explosion when the recording terminated in destruction")]
        public void Bug613_ResolvedAnchorLoopPauseFiresExplosion()
        {
            var (state, _) = RunBug613LoopPauseScenario(
                positionerSetsLoopRetireFlag: false);

            InGameAssert.IsTrue(state.explosionFired,
                "resolvable-anchor loop-pause endpoint must still fire TriggerExplosionIfDestroyed when terminal=Destroyed");
        }

        // -------------------------------------------------------------
        // Scenario harnesses
        // -------------------------------------------------------------

        private (GhostPlaybackEngine engine, GhostPlaybackState state, List<string> capturedLog)
            RunBug613EarlyDebrisScenario(bool positionerSetsRetireFlag)
        {
            var activeVessel = FlightGlobals.ActiveVessel;
            if (activeVessel == null || activeVessel.mainBody == null)
                InGameAssert.Skip("needs an active vessel with a main body");

            var positioner = new Bug613RetireBranchPositioner
            {
                SetsRetireFlag = positionerSetsRetireFlag,
            };
            var engine = new GhostPlaybackEngine(positioner);
            engine.ResolvePlaybackDistanceOverride =
                (recordingIndex, traj, ghostState, ut) => 0.0;
            engine.ResolvePlaybackActiveVesselDistanceOverride =
                (recordingIndex, traj, ghostState, ut) => 0.0;

            var ghost = new GameObject(
                positionerSetsRetireFlag
                    ? "ParsekTestGhost_Bug613EarlyDebris_Retired"
                    : "ParsekTestGhost_Bug613EarlyDebris_Resolved");
            runner.TrackForCleanup(ghost);
            ghost.SetActive(true);

            var state = new GhostPlaybackState
            {
                vesselName = "Bug613TestEarlyDebris",
                ghost = ghost,
                playbackIndex = 0,
            };
            engine.ghostStates[0] = state;

            // 5-second debris recording terminating Destroyed; an early
            // Destroyed PartEvent at 1.0s with current UT > 1.0 makes
            // TryGetEarlyDestroyedDebrisExplosionUT return true.
            var traj = new Bug613EarlyDebrisRelativeTrajectory(
                bodyName: activeVessel.mainBody.name,
                latitude: activeVessel.latitude,
                longitude: activeVessel.longitude,
                altitude: System.Math.Max(0.0, activeVessel.altitude));
            var flags = new[]
            {
                new TrajectoryPlaybackFlags
                {
                    chainEndUT = traj.EndUT,
                    recordingId = traj.RecordingId,
                    segmentLabel = traj.VesselName,
                }
            };

            // Capture the deferred completed list and dedupe set count via
            // engine internals (same assembly).
            var ctx = new FrameContext
            {
                currentUT = 2.5, // > early-debris explosion UT (1.0) but < EndUT (5.0)
                warpRate = 1f,
                warpRateIndex = 0,
                activeVesselPos = Vector3d.zero,
                protectedIndex = -1,
                protectedLoopCycleIndex = -1,
                externalGhostCount = 0,
                mapViewEnabled = false,
                autoLoopIntervalSeconds = 10.0,
            };

            var localLog = new List<string>();
            var priorObserver = ParsekLog.TestObserverForTesting;
            var priorVerbose = ParsekLog.VerboseOverrideForTesting;
            ParsekLog.ResetRateLimitsForTesting();
            ParsekLog.VerboseOverrideForTesting = true;
            ParsekLog.TestObserverForTesting = line =>
            {
                localLog.Add(line);
                priorObserver?.Invoke(line);
            };
            try
            {
                engine.UpdatePlayback(
                    new IPlaybackTrajectory[] { traj },
                    flags,
                    ctx);
            }
            finally
            {
                ParsekLog.TestObserverForTesting = priorObserver;
                ParsekLog.VerboseOverrideForTesting = priorVerbose;
            }
            return (engine, state, localLog);
        }

        private (List<CameraActionEvent> cameraEvents,
                 List<LoopRestartedEvent> restartEvents,
                 List<string> capturedLog,
                 GhostPlaybackState state)
            RunBug613LoopCycleScenario(bool positionerSetsLoopRetireFlag)
        {
            var activeVessel = FlightGlobals.ActiveVessel;
            if (activeVessel == null || activeVessel.mainBody == null)
                InGameAssert.Skip("needs an active vessel with a main body");

            var positioner = new Bug613RetireBranchPositioner
            {
                SetsRetireFlag = false,
                SetsLoopRetireFlag = positionerSetsLoopRetireFlag,
            };
            var engine = new GhostPlaybackEngine(positioner);
            engine.ResolvePlaybackDistanceOverride =
                (recordingIndex, traj, ghostState, ut) => 0.0;
            engine.ResolvePlaybackActiveVesselDistanceOverride =
                (recordingIndex, traj, ghostState, ut) => 0.0;

            var ghost = new GameObject(
                positionerSetsLoopRetireFlag
                    ? "ParsekTestGhost_Bug613LoopCycle_Retired"
                    : "ParsekTestGhost_Bug613LoopCycle_Resolved");
            runner.TrackForCleanup(ghost);
            ghost.SetActive(true);

            // State pre-seeded as if a previous cycle (loopCycleIndex=0) just
            // ended; this frame's currentUT is in cycle 1 so HasLoopCycleChanged
            // returns true and the cycle-endpoint side-effect block runs.
            var state = new GhostPlaybackState
            {
                vesselName = "Bug613TestLoopCycle",
                ghost = ghost,
                playbackIndex = 0,
                loopCycleIndex = 0,
            };
            engine.ghostStates[0] = state;

            var cameraEvents = new List<CameraActionEvent>();
            var restartEvents = new List<LoopRestartedEvent>();
            engine.OnLoopCameraAction += e => cameraEvents.Add(e);
            engine.OnLoopRestarted += e => restartEvents.Add(e);

            // 5-second LOOPING relative-frame recording terminating Destroyed
            // so the cycle-endpoint code computes needsExplosion and would
            // fire the camera/restart events. LoopIntervalSeconds=5 + currentUT=6
            // puts us in cycle index 1 (cycle change from 0).
            var traj = new Bug613LoopRelativeTrajectory(
                bodyName: activeVessel.mainBody.name,
                latitude: activeVessel.latitude,
                longitude: activeVessel.longitude,
                altitude: System.Math.Max(0.0, activeVessel.altitude),
                terminalDestroyed: true);
            var flags = new[]
            {
                new TrajectoryPlaybackFlags
                {
                    chainEndUT = double.PositiveInfinity,
                    recordingId = traj.RecordingId,
                    segmentLabel = traj.VesselName,
                }
            };

            var ctx = new FrameContext
            {
                currentUT = 6.0,
                warpRate = 1f,
                warpRateIndex = 0,
                activeVesselPos = Vector3d.zero,
                protectedIndex = -1,
                protectedLoopCycleIndex = -1,
                externalGhostCount = 0,
                mapViewEnabled = false,
                autoLoopIntervalSeconds = 5.0,
            };

            var localLog = new List<string>();
            var priorObserver = ParsekLog.TestObserverForTesting;
            var priorVerbose = ParsekLog.VerboseOverrideForTesting;
            ParsekLog.ResetRateLimitsForTesting();
            ParsekLog.VerboseOverrideForTesting = true;
            ParsekLog.TestObserverForTesting = line =>
            {
                localLog.Add(line);
                priorObserver?.Invoke(line);
            };
            try
            {
                engine.UpdatePlayback(
                    new IPlaybackTrajectory[] { traj },
                    flags,
                    ctx);
            }
            finally
            {
                ParsekLog.TestObserverForTesting = priorObserver;
                ParsekLog.VerboseOverrideForTesting = priorVerbose;
            }
            return (cameraEvents, restartEvents, localLog, state);
        }

        private (List<CameraActionEvent> cameraEvents,
                 List<OverlapExpiredEvent> expiredEvents,
                 List<string> capturedLog,
                 GhostPlaybackState ovState)
            RunBug613OverlapExpiryScenario(bool positionerSetsLoopRetireFlag)
        {
            var activeVessel = FlightGlobals.ActiveVessel;
            if (activeVessel == null || activeVessel.mainBody == null)
                InGameAssert.Skip("needs an active vessel with a main body");

            var positioner = new Bug613RetireBranchPositioner
            {
                SetsRetireFlag = false,
                SetsLoopRetireFlag = positionerSetsLoopRetireFlag,
            };
            var engine = new GhostPlaybackEngine(positioner);
            engine.ResolvePlaybackDistanceOverride =
                (recordingIndex, traj, ghostState, ut) => 0.0;
            engine.ResolvePlaybackActiveVesselDistanceOverride =
                (recordingIndex, traj, ghostState, ut) => 0.0;

            var primaryGhost = new GameObject("ParsekTestGhost_Bug613OverlapPrimary");
            var ovGhost = new GameObject(
                positionerSetsLoopRetireFlag
                    ? "ParsekTestGhost_Bug613OverlapExpiry_Retired"
                    : "ParsekTestGhost_Bug613OverlapExpiry_Resolved");
            runner.TrackForCleanup(primaryGhost);
            runner.TrackForCleanup(ovGhost);
            primaryGhost.SetActive(true);
            ovGhost.SetActive(true);

            // Overlap-loop trajectory: duration=10s, interval=5s ->
            // IsOverlapLoop(5,10)=true AND 5 >= LoopTiming.MinCycleDuration so
            // ResolveLoopInterval does not clamp. lastCycle = floor(11/5) = 2.
            //
            // Primary state must already be at cycleIndex=lastCycle so
            // primaryCycleChanged stays false (we want the overlap-expiry
            // branch, not the cycle-change demote/respawn branch).
            //
            // Overlap state (cycleIndex=0) has phase = 11 - 0*5 = 11s, which
            // exceeds duration=10s, so UpdateExpireAndPositionOverlaps walks
            // its expire branch and emits OnOverlapCameraAction +
            // OnOverlapExpired.
            //
            // Earlier (interval=2.0 / duration=5) clamped to interval=5 and
            // IsOverlapLoop(5,5)=false, so the overlap branch never ran and
            // the resolved-anchor assertion (cameraEvents.Count >= 1) failed
            // while the retired-anchor assertion (== 0) passed trivially.
            var primaryState = new GhostPlaybackState
            {
                vesselName = "Bug613TestOverlapPrimary",
                ghost = primaryGhost,
                playbackIndex = 0,
                loopCycleIndex = 2,
            };
            engine.ghostStates[0] = primaryState;

            var ovState = new GhostPlaybackState
            {
                vesselName = "Bug613TestOverlap",
                ghost = ovGhost,
                playbackIndex = 0,
                loopCycleIndex = 0,
            };
            engine.overlapGhosts[0] = new List<GhostPlaybackState> { ovState };

            var cameraEvents = new List<CameraActionEvent>();
            var expiredEvents = new List<OverlapExpiredEvent>();
            engine.OnOverlapCameraAction += e => cameraEvents.Add(e);
            engine.OnOverlapExpired += e => expiredEvents.Add(e);

            var traj = new Bug613LoopRelativeTrajectory(
                bodyName: activeVessel.mainBody.name,
                latitude: activeVessel.latitude,
                longitude: activeVessel.longitude,
                altitude: System.Math.Max(0.0, activeVessel.altitude),
                terminalDestroyed: true,
                loopIntervalSeconds: 5.0,
                durationSeconds: 10.0);
            var flags = new[]
            {
                new TrajectoryPlaybackFlags
                {
                    chainEndUT = double.PositiveInfinity,
                    recordingId = traj.RecordingId,
                    segmentLabel = traj.VesselName,
                }
            };

            var ctx = new FrameContext
            {
                currentUT = 11.0, // cycle 0 phase=11 > duration=10 -> expires; lastCycle=2
                warpRate = 1f,
                warpRateIndex = 0,
                activeVesselPos = Vector3d.zero,
                protectedIndex = -1,
                protectedLoopCycleIndex = -1,
                externalGhostCount = 0,
                mapViewEnabled = false,
                autoLoopIntervalSeconds = 5.0,
            };

            var localLog = new List<string>();
            var priorObserver = ParsekLog.TestObserverForTesting;
            var priorVerbose = ParsekLog.VerboseOverrideForTesting;
            ParsekLog.ResetRateLimitsForTesting();
            ParsekLog.VerboseOverrideForTesting = true;
            ParsekLog.TestObserverForTesting = line =>
            {
                localLog.Add(line);
                priorObserver?.Invoke(line);
            };
            try
            {
                engine.UpdatePlayback(
                    new IPlaybackTrajectory[] { traj },
                    flags,
                    ctx);
            }
            finally
            {
                ParsekLog.TestObserverForTesting = priorObserver;
                ParsekLog.VerboseOverrideForTesting = priorVerbose;
            }
            return (cameraEvents, expiredEvents, localLog, ovState);
        }

