                testName: "Pipeline_Anchor_RelativeBoundary",
                source: Parsek.Rendering.AnchorSource.RelativeBoundary,
                side: Parsek.Rendering.AnchorSide.End);
        }

        /// <summary>
        /// Phase 6 §7.5. OrbitalCheckpoint candidate on the ABSOLUTE side
